namespace example_template {

    schema GreetResult {
        message: String
    }

    event facet Greet(name: String) => (result: GreetResult)

    workflow Hello(name: String = "world") => (greeting: GreetResult) andThen {
        greeting = Greet(name = $.name)
    }
}

// Workflow with two sequential steps in one andThen block.
//
// Steps inside the same andThen block see each other's results.
// Reference a previous step's return as `step_name.attribute`.

namespace etl {
    event facet Fetch(url: String) => (body: String)
    event facet Parse(body: String) => (count: Long)

    workflow CountWords(url: String) => (count: Long) andThen {
        fetched = Fetch(url = $.url)
        parsed = Parse(body = fetched.body)
        yield CountWords(count = parsed.count)
    }
}

// save-earth — FFL definitions for the environmental-action map pipeline.
//
// Mirrors the CLI surface in ``save_earth/tools/`` — each
// event facet wraps one _save_earth_tools function, handlers are thin
// dispatchers that import from _save_earth_tools/ via a sys.path shim.
// The runtime and the
// terminal produce identical outputs and share the cache rooted at
// ``$AFL_CACHE_ROOT/save-earth/``.
//
// Data sources covered in this pass:
//   - OpenLitterMap (crowd-sourced geotagged litter observations)
//   - EPA Superfund NPL + Brownfields (authoritative remediation sites)
// Later PRs can add Tree Equity Score, Open311 cleanup feeds, and
// Surfrider chapters by defining new event facets in save_earth.sources
// without touching the map-build facet.

// ---------------------------------------------------------------------------
// Schemas
// ---------------------------------------------------------------------------

namespace save_earth.types {
    /** Result of any source download — one cached GeoJSON + sidecar.
      *
      * Matches the ``FetchResult`` dataclass the _save_earth_tools modules return so
      * FFL workflows can key downstream steps on ``relative_path`` or
      * ``feature_count`` without parsing the cached file. */
    schema SourceFetchResult {
        cache_type: String,
        relative_path: String,
        feature_count: Int,
        size_bytes: Int,
        sha256: String,
        source_url: String,
        was_cached: Boolean,
        used_mock: Boolean
    }

    /** Output of BuildMap: filesystem paths to the rendered bundle.
      *
      * ``layer_counts`` is ``{layer_name: feature_count}`` as a JSON
      * object so the schema stays flat even when new sources get
      * added later. */
    schema MapBundle {
        region_key: String,
        output_dir: String,
        html_path: String,
        layer_count: Int,
        layer_counts: Json
    }
}

// ---------------------------------------------------------------------------
// Shared mixins
// ---------------------------------------------------------------------------

namespace save_earth.mixins {
    /** Retry a step with exponential backoff. Applied to every
      * network-facing source download — OpenLitterMap's servers can
      * rate-limit, EPA's ArcGIS fronts occasionally 5xx. */
    facet RetryPolicy(
        max_retries: Int = 3,
        backoff_ms: Int = 2000
    ) => (max_retries: Int, backoff_ms: Int)

    implicit default_retry = RetryPolicy()
}

// ---------------------------------------------------------------------------
// Sources — one event facet per cached data source.
// ---------------------------------------------------------------------------

namespace save_earth.sources {
    use save_earth.types

    /** Download OpenLitterMap geotagged litter observations.
      *
      * ``mode = "clusters"`` (default) works at any zoom; returns
      * aggregated cluster points. ``mode = "points"`` returns
      * individual photos but the upstream server enforces
      * ``zoom >= 15`` and a bounded ``bbox``.
      *
      * ``bbox`` is a comma-separated ``min_lon,min_lat,max_lon,max_lat``
      * string (empty = no bbox). Keeping it a String avoids making
      * Json mandatory; handlers parse it at dispatch time. */
    event facet DownloadOpenLitterMap(
        mode: String = "clusters",
        zoom: Int = 4,
        bbox: String = "",
        force: Boolean = false,
        use_mock: Boolean = false
    ) => (
        cache_type: String,
        relative_path: String,
        feature_count: Int,
        size_bytes: Int,
        sha256: String,
        source_url: String,
        was_cached: Boolean,
        used_mock: Boolean
    ) with RetryPolicy()

    /** Download the EPA Toxic Release Inventory facility table.
      *
      * Fetches TRI_FACILITY from ``data.epa.gov/efservice/`` (the
      * old ``enviro.epa.gov`` URL redirects there). ~65 k rows
      * total, paginated at 10 k/request. Normalizes longitude sign
      * for western-hemisphere state codes.
      *
      * ``active_only`` (default true) drops facilities whose
      * ``fac_closed_ind`` is ``"1"``. */
    event facet DownloadTri(
        active_only: Boolean = true,
        force: Boolean = false,
        use_mock: Boolean = false
    ) => (
        cache_type: String,
        relative_path: String,
        feature_count: Int,
        size_bytes: Int,
        sha256: String,
        source_url: String,
        was_cached: Boolean,
        used_mock: Boolean
    ) with RetryPolicy()

    /** Download an EPA remediation-site dataset.
      *
      * ``dataset`` = ``"superfund"`` (NPL sites, ~1.4k) or
      * ``"brownfields"`` (ACRES, tens of thousands — paginated
      * transparently by the handler). */
    event facet DownloadEpaCleanups(
        dataset: String = "superfund",
        force: Boolean = false,
        use_mock: Boolean = false
    ) => (
        cache_type: String,
        relative_path: String,
        feature_count: Int,
        size_bytes: Int,
        sha256: String,
        source_url: String,
        was_cached: Boolean,
        used_mock: Boolean
    ) with RetryPolicy()
}

// ---------------------------------------------------------------------------
// Maps — stitch cached GeoJSON into a MapLibre HTML bundle.
// ---------------------------------------------------------------------------

namespace save_earth.maps {
    use save_earth.types

    /** Build a MapLibre HTML map with every cached save-earth layer.
      *
      * Auto-discovers cached files — every OpenLitterMap GeoJSON under
      * ``cache/save-earth/openlittermap/`` and every EPA dataset
      * becomes its own toggleable layer. Passing a dependency signal
      * (e.g. the ``feature_count`` from a just-finished download) lets
      * the runtime sequence the map build after the downloads it
      * relies on.
      *
      * ``basemap_url`` / ``basemap_attribution`` let the caller swap
      * the raster basemap. Default is CARTO Voyager — free, no API
      * key, works from ``file://`` (unlike tile.openstreetmap.org,
      * which requires a Referer header per its volunteer-tile
      * policy). Supports ``{z}/{x}/{y}`` plus optional ``{s}`` for
      * subdomain rotation. */
    event facet BuildMap(
        region: String = "global",
        center_lat: Double = 39.8283,
        center_lon: Double = -98.5795,
        zoom: Double = 4.0,
        basemap_url: String = "",
        basemap_attribution: String = "",
        dependency_signal: Int = 0
    ) => (
        region_key: String,
        output_dir: String,
        html_path: String,
        layer_count: Int,
        layer_counts: Json
    )
}

// ---------------------------------------------------------------------------
// Workflows
// ---------------------------------------------------------------------------

namespace save_earth.workflows {
    use save_earth.types

    /** Download every source and build the combined global map.
      *
      * Downloads run in parallel (FFL ``andThen`` siblings are
      * scheduled concurrently when they don't reference each other).
      * Any download failure yields ``partial_failure`` with a
      * describing ``detail`` but does not stop the map build — the
      * map-render tool skips absent layers gracefully. */
    workflow BuildGlobalMap(
        openlittermap_zoom: Int = 4,
        include_brownfields: Boolean = true,
        use_mock: Boolean = false
    ) => (
        status: String,
        html_path: String,
        detail: String
    ) andThen {
        olm = DownloadOpenLitterMap(
            mode = "clusters",
            zoom = $.openlittermap_zoom,
            use_mock = $.use_mock
        ) catch {
            yield BuildGlobalMap(
                status = "partial_failure",
                html_path = "",
                detail = "openlittermap download failed"
            )
        }
        superfund = DownloadEpaCleanups(
            dataset = "superfund",
            use_mock = $.use_mock
        ) catch {
            yield BuildGlobalMap(
                status = "partial_failure",
                html_path = "",
                detail = "epa superfund download failed"
            )
        }
        brownfields = DownloadEpaCleanups(
            dataset = "brownfields",
            use_mock = $.use_mock
        ) catch {
            yield BuildGlobalMap(
                status = "partial_failure",
                html_path = "",
                detail = "epa brownfields download failed"
            )
        }
        // dependency_signal pins the map build after every download
        // by referencing a field each produced — the runtime
        // resolves that as a data-flow edge.
        map = BuildMap(
            region = "global",
            dependency_signal = olm.feature_count + superfund.feature_count + brownfields.feature_count
        ) catch {
            yield BuildGlobalMap(
                status = "failed",
                html_path = "",
                detail = "map build failed"
            )
        }
        yield BuildGlobalMap(
            status = "completed",
            html_path = map.html_path,
            detail = "map " ++ map.region_key ++ " with " ++ map.layer_count ++ " layer(s)"
        )
    }

    /** Download OpenLitterMap at a tighter zoom for a specific region
      * (useful for country/state maps where the zoom-4 global feed is
      * too coarse). Chains into the global map build so the new layer
      * is picked up automatically. */
    workflow BuildRegionalMap(
        region_key: String = "us",
        openlittermap_zoom: Int = 8,
        center_lat: Double = 39.8283,
        center_lon: Double = -98.5795,
        zoom: Double = 4.0,
        use_mock: Boolean = false
    ) => (status: String, html_path: String) andThen {
        olm = DownloadOpenLitterMap(
            mode = "clusters",
            zoom = $.openlittermap_zoom,
            use_mock = $.use_mock
        ) catch {
            yield BuildRegionalMap(status = "partial_failure", html_path = "")
        }
        superfund = DownloadEpaCleanups(
            dataset = "superfund",
            use_mock = $.use_mock
        ) catch {
            yield BuildRegionalMap(status = "partial_failure", html_path = "")
        }
        map = BuildMap(
            region = $.region_key,
            center_lat = $.center_lat,
            center_lon = $.center_lon,
            zoom = $.zoom,
            dependency_signal = olm.feature_count + superfund.feature_count
        ) catch {
            yield BuildRegionalMap(status = "failed", html_path = "")
        }
        yield BuildRegionalMap(
            status = "completed",
            html_path = map.html_path
        )
    }
}

// OSM Geocoder — resolve addresses to geographic coordinates
//
// This workflow accepts an address string, dispatches it to the
// Geocode event facet (handled by an external agent), and returns
// the latitude/longitude result.

/** Address-to-coordinate geocoding using OSM Nominatim. */
namespace osm.geocode {

    /** Geographic coordinate with human-readable display name. */
    schema GeoCoordinate {
        lat: String,
        lon: String,
        display_name: String
    }

    /** Resolves a street address to geographic coordinates via an external geocoding agent. */
    event facet Geocode(address: String) => (result: GeoCoordinate)

    /** Geocodes a single address and returns its coordinates. */
    workflow GeocodeAddress(address: String) => (location: GeoCoordinate) andThen {
        geo = Geocode(address = $.address)
        yield GeocodeAddress(location = geo.result)
    }

    /** Geocodes multiple addresses in parallel using foreach iteration. */
    workflow GeocodeAll(addresses: Json) => (locations: Json) andThen foreach addr in $.addresses {
        geo = Geocode(address = addr.value)
        yield GeocodeAll(locations = geo.result)
    }

}


/** Air quality data schemas and event facets for OpenAQ integration. */
namespace osm.AirQuality {
    /** Air quality sensor readings within a bounding box. */
    schema AirQualityResult {
        output_path: String,
        station_count: Long,
        parameter: String,
        avg_value: Double,
        unit: String,
        format: String
    }

    /** Result of correlating schools with nearest air quality sensors. */
    schema ExposureCorrelationResult {
        output_path: String,
        school_count: Long,
        matched_count: Long,
        high_exposure: Long,
        medium_exposure: Long,
        low_exposure: Long,
        avg_pm25: Double,
        format: String
    }

    /** Aggregate exposure statistics with WHO PM2.5 thresholds. */
    schema ExposureStats {
        total_schools: Long,
        matched_schools: Long,
        high_count: Long,
        medium_count: Long,
        low_count: Long,
        high_pct: Double,
        medium_pct: Double,
        low_pct: Double,
        avg_pm25: Double,
        max_pm25: Double,
        min_pm25: Double
    }

    /** Fetches air quality readings from OpenAQ within a bounding box.
     * @param bbox Bounding box string for the query area
     * @param parameter Air quality parameter to measure (default: pm25)
     * @param radius_m Search radius in meters around each point
     * @returns result Air quality readings with station count and averages
     */
    event facet FetchAirQuality(bbox: String,
        parameter: String = "pm25",
        radius_m: Long = 25000) => (result: AirQualityResult)

    /** Correlates schools with nearest air quality sensor.
     * Classifies exposure: high >= 35, medium 15-35, low < 15 ug/m3 (WHO PM2.5).
     * @param schools_path Path to GeoJSON file of school locations
     * @param air_quality_path Path to GeoJSON file of air quality readings
     * @param max_distance_km Maximum matching distance in kilometers
     * @returns result Correlation results with exposure classification counts
     */
    event facet CorrelateSchoolAirQuality(schools_path: String,
        air_quality_path: String,
        max_distance_km: Double = 10) => (result: ExposureCorrelationResult)

    /** Computes aggregate exposure statistics from correlated school-sensor data.
     * @param input_path Path to the correlated exposure GeoJSON file
     * @returns stats Aggregate statistics including counts and percentages by exposure level
     */
    event facet ExposureStatistics(input_path: String) => (stats: ExposureStats)
}

/** School air quality exposure pipeline combining OSM schools with OpenAQ sensor data. */
namespace osm.SchoolAirQuality {
    use osm.types
    use osm.Region
    use osm.cache
    use osm.Amenities
    use osm.AirQuality
    use osm.viz

    /** Maps school air quality exposure: resolves a region, extracts schools, fetches OpenAQ data, correlates, and renders.
     * @param region Human-friendly region name to analyze
     * @param prefer_continent Continent hint for ambiguous region names
     * @param parameter Air quality parameter (default: pm25)
     * @param radius_m OpenAQ search radius in meters
     * @param max_distance_km Maximum school-to-sensor matching distance
     * @param title Map title
     * @param color Map marker color
     * @returns map_path Path to the rendered HTML map
     * @returns region_name Resolved region name
     * @returns school_count Total schools analyzed
     * @returns station_count Air quality stations found
     * @returns high_exposure Schools in high exposure zones
     * @returns medium_exposure Schools in medium exposure zones
     * @returns low_exposure Schools in low exposure zones
     * @returns avg_pm25 Average PM2.5 across matched schools
     * @returns max_pm25 Maximum PM2.5 across matched schools
     */
    workflow SchoolAirQualityMap(
        region: String,
        prefer_continent: String = "",
        parameter: String = "pm25",
        radius_m: Long = 25000,
        max_distance_km: Double = 10,
        title: String = "School Air Quality Exposure",
        color: String = "#e74c3c"
    ) => (
        map_path: String,
        region_name: String,
        school_count: Long,
        station_count: Long,
        high_exposure: Long,
        medium_exposure: Long,
        low_exposure: Long,
        avg_pm25: Double,
        max_pm25: Double
    ) andThen {

        // 1. Resolve region name to a typed Region
        resolved = ResolveRegion(
            name = $.region,
            prefer_continent = $.prefer_continent
        )

        // 2. Download (or reuse cached) PBF for the resolved region
        cached = osm.cache.Download(region = resolved.region)

        // 3. Extract schools from OSM
        schools = osm.Amenities.ExtractAmenities(
            cache = cached.cache,
            category = "education"
        )

        // 4. Fetch air quality stations from OpenAQ
        air = FetchAirQuality(
            bbox = resolved.region.geofabrik_path,
            parameter = $.parameter,
            radius_m = $.radius_m
        )

        // 4. Correlate each school with nearest sensor
        correlated = CorrelateSchoolAirQuality(
            schools_path = schools.result.output_path,
            air_quality_path = air.result.output_path,
            max_distance_km = $.max_distance_km
        )

        // 5. Compute exposure statistics
        stats = ExposureStatistics(
            input_path = correlated.result.output_path
        )

        // 6. Render color-coded map
        map = RenderMap(
            geojson_path = correlated.result.output_path,
            title = $.title,
            color = $.color
        )

        yield SchoolAirQualityMap(
            map_path = map.result.output_path,
            region_name = resolved.region.name,
            school_count = stats.stats.total_schools,
            station_count = air.result.station_count,
            high_exposure = stats.stats.high_count,
            medium_exposure = stats.stats.medium_count,
            low_exposure = stats.stats.low_count,
            avg_pm25 = stats.stats.avg_pm25,
            max_pm25 = stats.stats.max_pm25
        )
    }
}


// Amenity extraction from OSM data
//
// Extracts amenities by category:
// - Food: restaurants, cafes, bars, fast_food
// - Shopping: supermarket, mall, convenience
// - Services: bank, post_office, fuel
// - Healthcare: hospital, pharmacy, doctors
// - Education: school, university, library

/** Amenity extraction by category: food, shopping, services, healthcare, education, entertainment. */
namespace osm.Amenities {
    use osm.types

    /** Extracted amenity data with category and type metadata. */
    schema AmenityFeatures {
        output_path: String,
        feature_count: Long,
        amenity_category: String,
        amenity_types: String,
        format: String,
        extraction_date: String
    }

    /** Aggregate amenity counts by category with name and hours coverage. */
    schema AmenityStats {
        total_amenities: Long,
        food: Long,
        shopping: Long,
        services: Long,
        healthcare: Long,
        education: Long,
        entertainment: Long,
        transport: Long,
        other: Long,
        with_name: Long,
        with_opening_hours: Long
    }

    /** Extracts all amenities from a region, optionally filtered by category. */
    event facet ExtractAmenities(cache: OSMCache,
        category: String = "all") => (result: AmenityFeatures)

    /** Extracts restaurants. */
    event facet Restaurants(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts cafes. */
    event facet Cafes(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts bars. */
    event facet Bars(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts fast food outlets. */
    event facet FastFood(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts all food and drink amenities. */
    event facet FoodAndDrink(cache: OSMCache) => (result: AmenityFeatures)

    /** Extracts supermarkets. */
    event facet Supermarkets(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts shopping malls. */
    event facet ShoppingMalls(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts convenience stores. */
    event facet ConvenienceStores(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts all shopping amenities. */
    event facet AllShopping(cache: OSMCache) => (result: AmenityFeatures)

    /** Extracts banks. */
    event facet Banks(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts ATMs. */
    event facet ATMs(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts post offices. */
    event facet PostOffices(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts fuel stations. */
    event facet FuelStations(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts EV charging stations. */
    event facet EVCharging(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts parking facilities. */
    event facet Parking(cache: OSMCache) => (result: AmenityFeatures)

    /** Extracts hospitals. */
    event facet Hospitals(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts pharmacies. */
    event facet Pharmacies(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts doctors' offices. */
    event facet Doctors(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts all healthcare amenities. */
    event facet AllHealthcare(cache: OSMCache) => (result: AmenityFeatures)

    /** Extracts schools. */
    event facet Schools(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts universities. */
    event facet Universities(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts libraries. */
    event facet Libraries(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts all education amenities. */
    event facet AllEducation(cache: OSMCache) => (result: AmenityFeatures)

    /** Extracts cinemas. */
    event facet Cinemas(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts theatres. */
    event facet Theatres(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts nightclubs. */
    event facet Nightclubs(cache: OSMCache) => (result: AmenityFeatures)
    /** Extracts all entertainment amenities. */
    event facet AllEntertainment(cache: OSMCache) => (result: AmenityFeatures)

    /** Computes aggregate amenity statistics. */
    event facet AmenityStatistics(input_path: String) => (stats: AmenityStats)

    /** Filters pre-extracted amenities by category. */
    event facet FilterAmenitiesByCategory(input_path: String,
        category: String) => (result: AmenityFeatures)

    /** Searches amenities by name pattern. */
    event facet SearchAmenities(input_path: String,
        name_pattern: String) => (result: AmenityFeatures)
}


// Boundary extraction schemas and event facets

/** Administrative and natural boundary extraction from OSM data. */
namespace osm.Boundaries {
    use osm.types

    /** Extracted boundary data with admin level and feature count. */
    schema BoundaryFeatures {
        output_path: String,
        feature_count: Long,
        boundary_type: String,
        admin_levels: String,
        format: String,
        extraction_date: String
    }

    /** Extracts country boundaries (admin_level=2). */
    event facet CountryBoundaries(cache: OSMCache) => (result: BoundaryFeatures)
    /** Extracts state/province boundaries (admin_level=4). */
    event facet StateBoundaries(cache: OSMCache) => (result: BoundaryFeatures)
    /** Extracts county boundaries (admin_level=6). */
    event facet CountyBoundaries(cache: OSMCache) => (result: BoundaryFeatures)
    /** Extracts city boundaries (admin_level=8). */
    event facet CityBoundaries(cache: OSMCache) => (result: BoundaryFeatures)

    /** Extracts administrative boundaries at a configurable level. */
    event facet AdminBoundary(cache: OSMCache, admin_level: Long = 2) => (result: BoundaryFeatures)

    /** Extracts lake boundaries. */
    event facet LakeBoundaries(cache: OSMCache) => (result: BoundaryFeatures)
    /** Extracts forest boundaries. */
    event facet ForestBoundaries(cache: OSMCache) => (result: BoundaryFeatures)
    /** Extracts park boundaries. */
    event facet ParkBoundaries(cache: OSMCache) => (result: BoundaryFeatures)

    /** Extracts natural boundaries by configurable type (water, wood, etc.). */
    event facet NaturalBoundary(cache: OSMCache, natural_type: String = "water") => (result: BoundaryFeatures)
}


// Building extraction from OSM data
//
// Extracts building footprints with classification:
// - Residential, commercial, industrial, retail
// - Building height/levels for 3D visualization
// - Building attributes (name, address, etc.)

/** Building footprint extraction with classification and 3D height data. */
namespace osm.Buildings {
    use osm.types

    /** Extracted building data with type, area, and height metadata. */
    schema BuildingFeatures {
        output_path: String,
        feature_count: Long,
        building_type: String,
        total_area_km2: Double,
        with_height_data: Long,
        format: String,
        extraction_date: String
    }

    /** Aggregate building statistics by type with height and level data. */
    schema BuildingStats {
        total_buildings: Long,
        total_area_km2: Double,
        residential: Long,
        commercial: Long,
        industrial: Long,
        retail: Long,
        other: Long,
        avg_levels: Double,
        with_height: Long
    }

    /** Extracts all buildings from a region, optionally filtered by type. */
    event facet ExtractBuildings(cache: OSMCache,
        building_type: String = "all") => (result: BuildingFeatures)

    /** Extracts residential buildings. */
    event facet ResidentialBuildings(cache: OSMCache) => (result: BuildingFeatures)

    /** Extracts commercial buildings. */
    event facet CommercialBuildings(cache: OSMCache) => (result: BuildingFeatures)

    /** Extracts industrial buildings. */
    event facet IndustrialBuildings(cache: OSMCache) => (result: BuildingFeatures)

    /** Extracts retail buildings (shops, malls). */
    event facet RetailBuildings(cache: OSMCache) => (result: BuildingFeatures)

    /** Extracts buildings with height/levels data for 3D visualization. */
    event facet Buildings3D(cache: OSMCache) => (result: BuildingFeatures)

    /** Extracts buildings above a minimum area threshold. */
    event facet LargeBuildings(cache: OSMCache,
        min_area_m2: Double = 1000) => (result: BuildingFeatures)

    /** Computes aggregate building statistics. */
    event facet BuildingStatistics(input_path: String) => (stats: BuildingStats)

    /** Filters pre-extracted GeoJSON by building type. */
    event facet FilterBuildingsByType(input_path: String,
        building_type: String) => (result: BuildingFeatures)
}


/** Aggregates individual African country OSM data downloads. */
namespace osm.Africa.cache {
  use osm.types
  use osm.cache.Africa

  /** Caches each African country individually in parallel. */
  facet AfricaIndividually() => (cache: [OSMCache]) andThen {
    algeria = osm.cache.Africa.Algeria()
    angola = osm.cache.Africa.Angola()
    benin = osm.cache.Africa.Benin()
    botswana = osm.cache.Africa.Botswana()
