// Operational OSM facets shared by the cache namespaces and the composed
// analysis workflows. Currently just CacheRegion — the PBF download step
// every region facet (osm.cache.*) and analysis workflow starts from.
//
// Prerequisites: compile with osmtypes.ffl (defines osm.types.OSMCache).

/** Operational OSM facets — PBF cache management. */
namespace osm.ops {
    use osm.types

    /**
     * Downloads (or reuses the cached) Geofabrik PBF for a region and
     * returns it as an OSMCache handle for downstream extraction.
     *
     * @param region A Geofabrik path (`europe/liechtenstein`,
     *   `north-america/us/california`, `africa/algeria`) or a human-friendly
     *   name (`Liechtenstein`, `California`, `Algeria`) which is resolved to
     *   the best-matching download.
     * @return cache The cached PBF as an OSMCache (`{url, path, date, size, wasInCache}`).
     */
    event facet CacheRegion(region: String) => (cache: OSMCache)
}


// OSM region resolution — resolve human-friendly names to Geofabrik downloads
//
// Translates names like "Colorado", "UK", "the Alps" into OSMCache and
// Region structures suitable for downstream workflows.
//
// Prerequisites: Compile with osmtypes.afl

/** Resolves human-friendly region names to canonical Region records. */
namespace osm.Region {
    use osm.types

    /** Resolves a single region name to a canonical Region.
     *
     *  Returns only the resolved region — download is a separate step.
     *  The recommended pipeline:
     *
     *      resolved = osm.Region.ResolveRegion(name = $.region)
     *      cached = osm.cache.Download(region = resolved.region)
     *      // analysis on cached.cache; metadata via cached.cache.region.*
     *
     *  Per-name disambiguation via qualifier suffix is supported (no
     *  extra parameter needed):
     *      "Georgia, US"              → US state
     *      "Georgia (country)"        → country
     *      "north-america/us/georgia" → canonical-path passthrough
     *
     *  `prefer_continent` is a fallback hint for names that don't carry
     *  a qualifier suffix (e.g. "Georgia" + prefer_continent =
     *  "NorthAmerica").  When the name remains ambiguous, the handler
     *  returns the best-match Region; inspect downstream behavior or
     *  use ResolveRegions for explicit ambiguity diagnostics. */
    event facet ResolveRegion(name: String,
        prefer_continent: String = "") => (region: Region)

    /** Batch resolve. Continents, countries, subnational regions, and
     *  named geographic features ("Alps", "Scandinavia") may all
     *  appear in `names`.
     *
     *  Per-name disambiguation via qualifier suffix (no extra parameter):
     *    "Georgia, US"            → US state
     *    "Georgia"                → falls back to prefer_continent
     *    "Georgia (country)"      → country
     *    "Córdoba, ES" / ", AR"   → Spain / Argentina
     *    "north-america/us/georgia" — canonical paths pass through verbatim
     *
     *  `prefer_continent` is the batch-wide tiebreaker, applied only to
     *  names without a qualifier suffix.
     *
     *  When `strict = true`, any unresolved or ambiguous (no qualifier,
     *  no prefer_continent match) name causes the facet to fail. When
     *  false (default), partial results are returned and the caller
     *  inspects `diagnostics`.
     *
     *  Names that expand to multiple regions ("Alps") contribute all
     *  their constituents to `regions` and a single entry to
     *  `diagnostics.expanded` for traceability. */
    event facet ResolveRegions(names: [String],
        prefer_continent: String = "",
        strict: Boolean = false) => (regions: [Region], diagnostics: ResolutionDiagnostics)

    /** Enumerate the known region catalog, optionally filtered.
     *  Examples:
     *    ListRegions(level = "continent")           → all continents + Planet
     *    ListRegions(parent_canonical = "north-america/canada")
     *                                               → all Canadian provinces + territories
     *    ListRegions(level = "subnational", continent = "Europe")
     *                                               → European subnational extracts
     *  Useful for data-driven aggregator workflows that today hardcode
     *  every state/province/country by name. */
    event facet ListRegions(parent_canonical: String = "",
        level: String = "",
        continent: String = "") => (regions: [Region])
}


// Region-based elevation + map workflows
//
// Accept a human-friendly region name (e.g. "Colorado", "UK", "the Alps")
// and chain: ResolveRegion → route extraction → elevation → filter → map.
//
// Prerequisites: Compile with osmtypes.afl, osmregion.afl, osmroutes.afl,
//   osmelevation.afl, osmvisualization.afl

/** Region-name-driven pipelines that resolve a name, extract routes, filter by elevation, and render maps. */
namespace osm.RegionMap {
    use osm.types
    use osm.Region
    use osm.cache
    use osm.Routes
    use osm.Elevation
    use osm.viz

    /** Resolves a region name, extracts bicycle routes, filters by elevation, and renders a map. */
    workflow BicycleElevationMapByRegion(
        region: String,
        min_elevation_ft: Long = 4000,
        network: String = "*",
        prefer_continent: String = "",
        title: String = "High Elevation Cycling Routes",
        color: String = "#e74c3c"
    ) => (map_path: String, feature_count: Long, matched_count: Long, region_name: String) andThen {
        resolved = ResolveRegion(name = $.region, prefer_continent = $.prefer_continent)

        cached = osm.cache.Download(region = resolved.region)

        routes = BicycleRoutes(cache = cached.cache, network = $.network)

        enriched = EnrichWithElevation(input_path = routes.result.output_path)

        filtered = FilterByMaxElevation(
            input_path = enriched.result.output_path,
            min_max_elevation_ft = $.min_elevation_ft
        )

        map = RenderMap(
            geojson_path = filtered.result.output_path,
            title = $.title,
            color = $.color
        )

        yield BicycleElevationMapByRegion(
            map_path = map.result.output_path,
            feature_count = filtered.result.feature_count,
            matched_count = filtered.result.matched_count,
            region_name = resolved.region.name
        )
    }

    /** Resolves a region name, extracts hiking trails, filters by elevation, and renders a map. */
    workflow HikingElevationMapByRegion(
        region: String,
        min_elevation_ft: Long = 2000,
        network: String = "*",
        prefer_continent: String = "",
        title: String = "High Elevation Hiking Trails",
        color: String = "#e67e22"
    ) => (map_path: String, feature_count: Long, matched_count: Long, region_name: String) andThen {
        resolved = ResolveRegion(name = $.region, prefer_continent = $.prefer_continent)

        cached = osm.cache.Download(region = resolved.region)

        trails = HikingTrails(cache = cached.cache, network = $.network)

        enriched = EnrichWithElevation(input_path = trails.result.output_path)

        filtered = FilterByMaxElevation(
            input_path = enriched.result.output_path,
            min_max_elevation_ft = $.min_elevation_ft
        )

        map = RenderMap(
            geojson_path = filtered.result.output_path,
            title = $.title,
            color = $.color
        )

        yield HikingElevationMapByRegion(
            map_path = map.result.output_path,
            feature_count = filtered.result.feature_count,
            matched_count = filtered.result.matched_count,
            region_name = resolved.region.name
        )
    }

    /** Resolves a region name, extracts routes of any type, filters by elevation, and renders a map. */
    workflow RouteMapByRegion(
        region: String,
        route_type: String,
        min_elevation_ft: Long = 2000,
        network: String = "*",
        prefer_continent: String = "",
        title: String = "High Elevation Routes",
        color: String = "#3498db"
    ) => (map_path: String, feature_count: Long, matched_count: Long, region_name: String) andThen {
        resolved = ResolveRegion(name = $.region, prefer_continent = $.prefer_continent)

        cached = osm.cache.Download(region = resolved.region)

        routes = osm.Routes.ExtractRoutes(
            cache = cached.cache,
            route_type = $.route_type,
            network = $.network
        )

        enriched = EnrichWithElevation(input_path = routes.result.output_path)

        filtered = FilterByMaxElevation(
            input_path = enriched.result.output_path,
            min_max_elevation_ft = $.min_elevation_ft
        )

        map = RenderMap(
            geojson_path = filtered.result.output_path,
            title = $.title,
            color = $.color
        )

        yield RouteMapByRegion(
            map_path = map.result.output_path,
            feature_count = filtered.result.feature_count,
            matched_count = filtered.result.matched_count,
            region_name = resolved.region.name
        )
    }
}


