/** Shared type definitions used across all OSM modules. */
namespace osm.types {
   /** Canonical identity for an OSM extract.
    *  Carries enough metadata to download the extract and to reason about
    *  hierarchy (continent ↔ country ↔ subnational ↔ feature).
    *
    *  Level vocabulary (closed set, for filtering by ListRegions):
    *    "planet"       — the whole-planet extract
    *    "continent"    — Africa, Europe, Asia, Russia (Geofabrik top-level)
    *    "country"      — France, Brazil, Algeria, ...
    *    "subnational"  — US states, Canadian provinces + territories,
    *                     German Länder, UK constituent countries
    *    "feature"      — named groupings ("Alps", "Scandinavia",
    *                     "PacificNorthwest")
    *
    *  level_label is Geofabrik's human term ("state", "province",
    *  "territory", "Land", "constituent country", "region") for display.
    *  continent follows Geofabrik's tree placement and may be "" for
    *  top-level extracts (Russia, Antarctica, Planet). */
   schema Region {
      query: String,
      name: String,
      canonical: String,
      level: String,
      level_label: String,
      parent_canonical: String,
      continent: String,
      geofabrik_path: String
   }

   /** Cached OSM data file with download metadata.
    *
    *  The embedded ``region`` is the canonical identity of the extract —
    *  downstream handlers read ``cache.region.name`` for display,
    *  ``cache.region.canonical`` as a stable id, and
    *  ``cache.region.geofabrik_path`` for the download path. Always
    *  populated: when the source is a plain path string (the legacy
    *  ``osm.ops.CacheRegion`` entry point), the handler resolves it back
    *  to a Region before constructing the cache. */
   schema OSMCache {
      region: Region,
      url: String,
      path: String,
      date: String,
      size: Long,
      wasInCache: Boolean
   }

   /** One ambiguous resolution kept for caller review.
    *  `chosen` is the best guess actually returned in `regions`;
    *  `candidates` is the full set ordered by score. */
   schema AmbiguousMatch {
      query: String,
      chosen: Region,
      candidates: [Region]
   }

   /** A name that expanded into multiple regions (e.g. "Alps" → 7 countries). */
   schema FeatureExpansion {
      query: String,
      feature_name: String,
      regions: [Region]
   }

   /** Side-channel report from ResolveRegions. Inspect to decide
    *  whether to proceed, prompt the user, or abort. */
   schema ResolutionDiagnostics {
      unresolved: [String],
      ambiguous: [AmbiguousMatch],
      expanded: [FeatureExpansion]
   }

   /** Cached GraphHopper routing graph built from OSM data. */
   schema GraphHopperCache {
      osmSource: String,
      graphDir: String,
      profile: String,
      date: String,
      size: Long,
      wasInCache: Boolean,
      version: String,
      nodeCount: Long,
      edgeCount: Long
   }

   /** Rendered HTML map page for a region — MapLibre GL JS + PMTiles. Points at a static directory under `html/<region>-latest/` with an index.html + style.json. `sources` lists the vector_tiles layers (water, parks, roads_routable, …) currently styled on the page. */
   schema HTMLMapCache {
      region: String,
      htmlDir: String,
      indexUrl: String,
      sources: [String],
      size: Long,
      date: String,
      wasInCache: Boolean,
      styleVersion: Long
   }

   /** Valhalla routing tileset built from OSM data. Profiles (auto, bicycle, pedestrian, truck, ...) are query-time costing models, not part of the build, so there is no per-profile field here — one tileset serves every profile. */
   schema ValhallaCache {
      osmSource: String,
      tileDir: String,
      date: String,
      size: Long,
      wasInCache: Boolean,
      version: String,
      tileCount: Long
   }

   /** pgRouting topology built from OSM road network data. */
   schema RoutingTopology {
      postgisUrl: String,
      region: String,
      profile: String,
      nodeCount: Long,
      edgeCount: Long,
      date: String,
      wasCached: Boolean
   }

   /** GTFS public transit feed with agency and shape metadata. */
   schema GTFSFeed {
