/** Aggregates all continental OSM caches into a single world-level dataset. */
namespace osm.World.cache {
    use osm.types
    use osm.Africa.cache
    use osm.Australia.cache
    use osm.Canada.cache
    use osm.CentralAmerica.cache
    use osm.Europe.cache
    use osm.NorthAmerica.cache
    use osm.SouthAmerica.cache
    use osm.UnitedStates.cache


    /** Downloads and caches OSM data for every continent, returning the combined result. */
    facet World() => (cache: [OSMCache]) andThen {

        // These broadcast the requests to the download services
        // If they are already cache, then just the locations are returned.
        // If not, then they are downloaded and cached.
        // As many OSM services as you got will get the requests and
        // participate in the downloads.

        africa = AfricaIndividually()
        australia = AustraliaIndividually()
        canada = CanadaIndividually()
        centralAmerica = CentralAmericaIndividually()
        europe = EuropeIndividually()
        northAmerica = NorthAmericaIndividually()
        southAmerica = SouthAmericaIndividually()
        unitedStatesAmerica = UnitedStatesIndividually()

        yield World(cache = africa.cache ++
                australia.cache ++
                canada.cache ++
                centralAmerica.cache ++
                europe.cache ++
                northAmerica.cache ++
                southAmerica.cache ++
                unitedStatesAmerica.cache)
    }
}




/** Single-pass multi-category OSM extraction for efficient PBF processing. */
namespace osm.Combined {
    use osm.types

    /** Single-pass multi-category extraction from a PBF file.
     *
     * Instead of running separate extraction steps for roads, amenities,
     * parks, etc., this facet scans the PBF once and extracts all
     * requested categories in parallel.
     *
     * Categories: amenities, population, roads, routes, parks, buildings, boundaries
     */
    event facet CombinedScan(
        cache: OSMCache,
        categories: [String]
    ) => (
        results: String,
        total_features: Long,
        scan_duration: Double,
        category_count: Long
    ) with Timeout(minutes = 120)

    /** Extracts a single category's output path from CombinedScan results.
     *
     * Parses the JSON results string from CombinedScan and returns the
     * output_path and feature_count for the requested category.
     */
    event facet ExtractCategoryResult(
        results: String,
        category: String
    ) => (
        output_path: String,
        feature_count: Long
    )
}


