// Composed Workflows - Demonstrating Facet-Based Composition
//
// These workflows show how to combine multiple facets together:
// - Cache facets for region data
// - Extraction facets for specific features
// - Filter facets for refining results
// - Statistics facets for analysis
// - Visualization facets for output
//
// This demonstrates the power of facet-based workflow composition.

/** Multi-stage composition patterns demonstrating cache, extraction, filtering, statistics, and visualization. */
namespace osm.workflows {
    use osm.types

    // ==========================================================================
    // PATTERN 1: Cache → Extract → Visualize
    // Basic three-stage pipeline for quick visualization
    // ==========================================================================

    /** Caches a region, extracts bicycle routes, and renders them on a map (three-stage pipeline). */
    workflow VisualizeBicycleRoutes(region: String = "Liechtenstein") => (map_path: String, route_count: Long) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        f = VisualizeBicycleRoutesFromCache(cache = cache.cache)
        yield VisualizeBicycleRoutes(map_path = f.map_path, route_count = f.route_count)
    }

    /** Cache-dependent logic for VisualizeBicycleRoutes. */
    facet VisualizeBicycleRoutesFromCache(cache: OSMCache) => (map_path: String, route_count: Long) andThen {
        routes = osm.Routes.BicycleRoutes(cache = $.cache, include_infrastructure = true)
        map = osm.viz.RenderMap(
            geojson_path = routes.result.output_path,
            title = "Bicycle Routes",
            color = "#27ae60"
        )
        yield VisualizeBicycleRoutesFromCache(map_path = map.result.output_path, route_count = routes.result.feature_count)
    }

    // ==========================================================================
    // PATTERN 2: Cache → Extract → Statistics
    // Analysis pipeline without visualization
    // ==========================================================================

    /** Extracts all parks from a region and computes aggregate statistics without visualization. */
    workflow AnalyzeParks(region: String = "Liechtenstein") => (total_parks: Long, total_area: Double, national: Long, state: Long) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        f = AnalyzeParksFromCache(cache = cache.cache)
        yield AnalyzeParks(
            total_parks = f.total_parks,
            total_area = f.total_area,
            national = f.national,
            state = f.state
        )
    }

    /** Cache-dependent logic for AnalyzeParks. */
    facet AnalyzeParksFromCache(cache: OSMCache) => (total_parks: Long, total_area: Double, national: Long, state: Long) andThen {
        parks = osm.Parks.ExtractParks(cache = $.cache, park_type = "all")
        stats = osm.Parks.ParkStatistics(input_path = parks.result.output_path)
        yield AnalyzeParksFromCache(
            total_parks = stats.stats.total_parks,
            total_area = stats.stats.total_area_km2,
            national = stats.stats.national_parks,
            state = stats.stats.state_parks
        )
    }

    // ==========================================================================
    // PATTERN 3: Cache → Extract → Filter → Visualize
    // Four-stage pipeline with filtering
    // ==========================================================================

    /** Extracts cities, filters by minimum population, and renders the qualifying cities on a map. */
    workflow LargeCitiesMap(region: String = "Liechtenstein", min_pop: Long = 10000) => (map_path: String, city_count: Long) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        f = LargeCitiesMapFromCache(cache = cache.cache, min_pop = $.min_pop)
        yield LargeCitiesMap(map_path = f.map_path, city_count = f.city_count)
    }

    /** Cache-dependent logic for LargeCitiesMap. */
    facet LargeCitiesMapFromCache(cache: OSMCache, min_pop: Long = 10000) => (map_path: String, city_count: Long) andThen {
        cities = osm.Population.Cities(cache = $.cache, min_population = 0)
        large = osm.Population.FilterByPopulation(
            input_path = cities.result.output_path,
            min_population = $.min_pop,
            place_type = "city",
            operator = "gte"
        )
        map = osm.viz.RenderMap(
            geojson_path = large.result.output_path,
            title = "Large Cities",
            color = "#e74c3c"
        )
        yield LargeCitiesMapFromCache(map_path = map.result.output_path, city_count = large.result.feature_count)
    }

    // ==========================================================================
    // PATTERN 4: Cache → Multiple Extractions → Combine Statistics
    // Parallel extraction with aggregated analysis
    // ==========================================================================

    /** Extracts bicycle, hiking, train, and bus routes in parallel and aggregates length statistics. */
    workflow TransportOverview(region: String = "Liechtenstein") => (bicycle_km: Double, hiking_km: Double, train_km: Double, bus_routes: Long) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        f = TransportOverviewFromCache(cache = cache.cache)
        yield TransportOverview(
            bicycle_km = f.bicycle_km,
            hiking_km = f.hiking_km,
            train_km = f.train_km,
            bus_routes = f.bus_routes
        )
    }

    /** Cache-dependent logic for TransportOverview. */
    facet TransportOverviewFromCache(cache: OSMCache) => (bicycle_km: Double, hiking_km: Double, train_km: Double, bus_routes: Long) andThen {
        bicycle = osm.Routes.BicycleRoutes(cache = $.cache, include_infrastructure = false)
        hiking = osm.Routes.HikingTrails(cache = $.cache, include_infrastructure = false)
        train = osm.Routes.TrainRoutes(cache = $.cache, include_infrastructure = false)
        bus = osm.Routes.BusRoutes(cache = $.cache, include_infrastructure = false)
        bicycle_stats = osm.Routes.RouteStatistics(input_path = bicycle.result.output_path)
        hiking_stats = osm.Routes.RouteStatistics(input_path = hiking.result.output_path)
        train_stats = osm.Routes.RouteStatistics(input_path = train.result.output_path)
        bus_stats = osm.Routes.RouteStatistics(input_path = bus.result.output_path)
        yield TransportOverviewFromCache(
            bicycle_km = bicycle_stats.stats.total_length_km,
            hiking_km = hiking_stats.stats.total_length_km,
            train_km = train_stats.stats.total_length_km,
            bus_routes = bus_stats.stats.route_count
        )
    }

    // ==========================================================================
    // PATTERN 5: Cache → Extract → Filter → Statistics → Visualize
    // Full five-stage pipeline
    // ==========================================================================

    /** Extracts parks, filters to national parks, computes area statistics, and renders a map. */
    workflow NationalParksAnalysis(region: String = "Liechtenstein") => (map_path: String, park_count: Long, total_area: Double, avg_area: Double) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        f = NationalParksAnalysisFromCache(cache = cache.cache)
        yield NationalParksAnalysis(
            map_path = f.map_path,
            park_count = f.park_count,
            total_area = f.total_area,
            avg_area = f.avg_area
        )
    }

    /** Cache-dependent logic for NationalParksAnalysis. */
    facet NationalParksAnalysisFromCache(cache: OSMCache) => (map_path: String, park_count: Long, total_area: Double, avg_area: Double) andThen {
        all_parks = osm.Parks.ExtractParks(cache = $.cache, park_type = "all")
        national = osm.Parks.FilterParksByType(
            input_path = all_parks.result.output_path,
            park_type = "national"
        )
        stats = osm.Parks.ParkStatistics(input_path = national.result.output_path)
        map = osm.viz.RenderMap(
            geojson_path = national.result.output_path,
            title = "National Parks",
            color = "#2ecc71"
        )
        yield NationalParksAnalysisFromCache(
            map_path = map.result.output_path,
            park_count = stats.stats.total_parks,
            total_area = stats.stats.total_area_km2,
            avg_area = stats.stats.total_area_km2
        )
    }

    // ==========================================================================
    // PATTERN 6: Parameterized City Analysis
    // Region and population threshold as parameters
    // ==========================================================================

    /** Extracts cities above a population threshold, computes statistics, and renders a map. */
    workflow CityAnalysis(region: String = "Liechtenstein", min_population: Long = 100000) => (map_path: String, large_cities: Long, total_pop: Long) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        f = CityAnalysisFromCache(cache = cache.cache, min_population = $.min_population)
        yield CityAnalysis(
            map_path = f.map_path,
            large_cities = f.large_cities,
            total_pop = f.total_pop
        )
    }

    /** Cache-dependent logic for CityAnalysis. */
    facet CityAnalysisFromCache(cache: OSMCache, min_population: Long = 100000) => (map_path: String, large_cities: Long, total_pop: Long) andThen {
        cities = osm.Population.Cities(cache = $.cache, min_population = $.min_population)
        stats = osm.Population.PopulationStatistics(
            input_path = cities.result.output_path,
            place_type = "city"
        )
        map = osm.viz.RenderMap(
            geojson_path = cities.result.output_path,
            title = "Cities",
            color = "#3498db"
        )
        yield CityAnalysisFromCache(
            map_path = map.result.output_path,
            large_cities = stats.stats.total_places,
            total_pop = stats.stats.total_population
        )
    }

    // ==========================================================================
    // PATTERN 7: Multi-Layer Visualization
    // Combining multiple extractions into one visual output
    // ==========================================================================

    /** Extracts bicycle and hiking routes and renders the bicycle layer on a map. */
    workflow TransportMap(region: String = "Liechtenstein") => (map_path: String) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        f = TransportMapFromCache(cache = cache.cache)
        yield TransportMap(map_path = f.map_path)
    }

    /** Cache-dependent logic for TransportMap. */
    facet TransportMapFromCache(cache: OSMCache) => (map_path: String) andThen {
        bicycle = osm.Routes.BicycleRoutes(cache = $.cache, include_infrastructure = false)
        hiking = osm.Routes.HikingTrails(cache = $.cache, include_infrastructure = false)
        bicycle_map = osm.viz.RenderMap(
            geojson_path = bicycle.result.output_path,
            title = "Bicycle Routes",
            color = "#27ae60"
        )
        yield TransportMapFromCache(map_path = bicycle_map.result.output_path)
    }

    // ==========================================================================
    // PATTERN 8: Boundary Analysis Pipeline
    // Administrative boundary extraction with filtering
    // ==========================================================================

    /** Extracts state-level administrative boundaries and renders them on a map with counts. */
    workflow StateBoundariesWithStats(region: String = "Liechtenstein") => (map_path: String, state_count: Long) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        f = StateBoundariesWithStatsFromCache(cache = cache.cache)
        yield StateBoundariesWithStats(
            map_path = f.map_path,
            state_count = f.state_count
        )
    }

    /** Cache-dependent logic for StateBoundariesWithStats. */
    facet StateBoundariesWithStatsFromCache(cache: OSMCache) => (map_path: String, state_count: Long) andThen {
        boundaries = osm.Boundaries.StateBoundaries(cache = $.cache)
        map = osm.viz.RenderMap(
            geojson_path = boundaries.result.output_path,
            title = "State Boundaries",
            color = "#9b59b6"
        )
        yield StateBoundariesWithStatsFromCache(
            map_path = map.result.output_path,
            state_count = boundaries.result.feature_count
        )
    }

    // ==========================================================================
    // PATTERN 9: POI Discovery Pipeline
    // Find and visualize points of interest
    // ==========================================================================

    /** Discovers cities, towns, and villages in a region and renders cities on a map. */
    workflow DiscoverCitiesAndTowns(region: String = "Liechtenstein") => (map_path: String, cities: Long, towns: Long, villages: Long) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        f = DiscoverCitiesAndTownsFromCache(cache = cache.cache)
        yield DiscoverCitiesAndTowns(
            map_path = f.map_path,
            cities = f.cities,
            towns = f.towns,
            villages = f.villages
        )
    }

    /** Cache-dependent logic for DiscoverCitiesAndTowns. */
    facet DiscoverCitiesAndTownsFromCache(cache: OSMCache) => (map_path: String, cities: Long, towns: Long, villages: Long) andThen {
        city_data = osm.POIs.Cities(cache = $.cache)
        town_data = osm.POIs.Towns(cache = $.cache)
        village_data = osm.POIs.Villages(cache = $.cache)
        map = osm.viz.RenderMap(
            geojson_path = city_data.cities.path,
            title = "Cities",
            color = "#e74c3c"
        )
        yield DiscoverCitiesAndTownsFromCache(
            map_path = map.result.output_path,
            cities = city_data.cities.size,
            towns = town_data.towns.size,
            villages = village_data.villages.size
        )
    }

    // ==========================================================================
    // PATTERN 10: Complete Regional Analysis
    // Comprehensive analysis combining multiple feature types
    // ==========================================================================

    /** Comprehensive analysis extracting parks, routes, and cities with statistics and a park map overlay. */
    workflow RegionalAnalysis(region: String = "Liechtenstein") => (parks_count: Long, parks_area: Double, routes_km: Double, cities_count: Long, map_path: String) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        f = RegionalAnalysisFromCache(cache = cache.cache)
        yield RegionalAnalysis(
            parks_count = f.parks_count,
            parks_area = f.parks_area,
            routes_km = f.routes_km,
            cities_count = f.cities_count,
            map_path = f.map_path
        )
    }

    /** Cache-dependent logic for RegionalAnalysis. */
    facet RegionalAnalysisFromCache(cache: OSMCache) => (parks_count: Long, parks_area: Double, routes_km: Double, cities_count: Long, map_path: String) andThen {
        parks = osm.Parks.ExtractParks(cache = $.cache, park_type = "all")
        routes = osm.Routes.BicycleRoutes(cache = $.cache, include_infrastructure = false)
        cities = osm.Population.Cities(cache = $.cache, min_population = 0)
        park_stats = osm.Parks.ParkStatistics(input_path = parks.result.output_path)
        route_stats = osm.Routes.RouteStatistics(input_path = routes.result.output_path)
        city_stats = osm.Population.PopulationStatistics(
            input_path = cities.result.output_path,
            place_type = "city"
        )
        map = osm.viz.RenderMap(
            geojson_path = parks.result.output_path,
            title = "Regional Overview - Parks",
            color = "#2ecc71"
        )
        yield RegionalAnalysisFromCache(
            parks_count = park_stats.stats.total_parks,
            parks_area = park_stats.stats.total_area_km2,
            routes_km = route_stats.stats.total_length_km,
            cities_count = city_stats.stats.total_places,
            map_path = map.result.output_path
        )
    }

    // ==========================================================================
    // PATTERN 11: Cache → Validate → Summary
    // Data quality validation pipeline
    // ==========================================================================

    /** Validates a cached region's OSM data and produces a summary of valid/invalid entries. */
    workflow ValidateAndSummarize(region: String = "Liechtenstein", output_dir: String = "/Volumes/afl_data/output/osm") => (total: Long, valid: Long, invalid: Long, output_path: String) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        f = ValidateAndSummarizeFromCache(cache = cache.cache, output_dir = $.output_dir)
        yield ValidateAndSummarize(
            total = f.total,
            valid = f.valid,
            invalid = f.invalid,
            output_path = f.output_path
        )
    }

    /** Cache-dependent logic for ValidateAndSummarize. */
    facet ValidateAndSummarizeFromCache(cache: OSMCache, output_dir: String = "/Volumes/afl_data/output/osm") => (total: Long, valid: Long, invalid: Long, output_path: String) andThen {
        validation = osm.ops.Validation.ValidateCache(
            cache = $.cache,
            output_dir = $.output_dir,
            use_hdfs = false
        )
        summary = osm.ops.Validation.ValidationSummary(
            input_path = validation.result.output_path
        )
        yield ValidateAndSummarizeFromCache(
            total = summary.stats.total_entries,
            valid = summary.stats.valid_entries,
            invalid = summary.stats.invalid_entries,
            output_path = validation.result.output_path
        )
    }

    // ==========================================================================
    // PATTERN 12: Cache → Local Verify → Summary
    // Standalone local PBF quality analysis via OSMOSE verifier
    // ==========================================================================

    /** Runs OSMOSE local verification on a region's PBF and summarizes geometry/tag/reference issues. */
    workflow OsmoseQualityCheck(
        region: String = "Liechtenstein",
        output_dir: String = "/Volumes/afl_data/output/osm"
    ) => (
        total_issues: Long,
        geometry_issues: Long,
        tag_issues: Long,
        reference_issues: Long,
        tag_coverage_pct: Double,
        output_path: String
    ) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        f = OsmoseQualityCheckFromCache(cache = cache.cache, output_dir = $.output_dir)
        yield OsmoseQualityCheck(
            total_issues = f.total_issues,
            geometry_issues = f.geometry_issues,
            tag_issues = f.tag_issues,
            reference_issues = f.reference_issues,
            tag_coverage_pct = f.tag_coverage_pct,
            output_path = f.output_path
        )
    }

    /** Cache-dependent logic for OsmoseQualityCheck. */
    facet OsmoseQualityCheckFromCache(cache: OSMCache, output_dir: String = "/Volumes/afl_data/output/osm") => (
        total_issues: Long,
        geometry_issues: Long,
        tag_issues: Long,
        reference_issues: Long,
        tag_coverage_pct: Double,
        output_path: String
    ) andThen {
        verify = osm.ops.OSMOSE.VerifyAll(
            cache = $.cache,
            output_dir = $.output_dir
        )
        summary = osm.ops.OSMOSE.ComputeVerifySummary(
            input_path = verify.result.output_path
        )
        yield OsmoseQualityCheckFromCache(
            total_issues = summary.summary.total_issues,
            geometry_issues = summary.summary.geometry_issues,
            tag_issues = summary.summary.tag_issues,
            reference_issues = summary.summary.reference_issues,
            tag_coverage_pct = summary.summary.tag_coverage_pct,
            output_path = verify.result.output_path
        )
    }

    // ==========================================================================
    // PATTERN 13: GTFS Transit Analysis
    // Download feed → parallel extract stops + routes → statistics
    // ==========================================================================

    /** Downloads a GTFS feed, extracts stops and routes in parallel, and computes transit statistics. */
    workflow TransitAnalysis(
        gtfs_url: String
    ) => (
        agency_name: String,
        stop_count: Long,
        route_count: Long,
        trip_count: Long,
        has_shapes: Boolean,
        stops_path: String,
        routes_path: String
    ) andThen {
        // Stage 1: Download and cache the GTFS feed
        dl = osm.Transit.GTFS.DownloadFeed(url = $.gtfs_url)

        // Stage 2: Extract stops and routes in parallel
        stops = osm.Transit.GTFS.ExtractStops(feed = dl.feed)
        routes = osm.Transit.GTFS.ExtractRoutes(feed = dl.feed)

        // Stage 3: Compute aggregate statistics
        stats = osm.Transit.GTFS.TransitStatistics(feed = dl.feed)

        yield TransitAnalysis(
            agency_name = stats.stats.agency_name,
            stop_count = stats.stats.stop_count,
            route_count = stats.stats.route_count,
            trip_count = stats.stats.trip_count,
            has_shapes = stats.stats.has_shapes,
            stops_path = stops.result.output_path,
            routes_path = routes.result.output_path
        )
    }

    // ==========================================================================
    // PATTERN 14: GTFS Transit Accessibility
    // OSM cache + GTFS feed → extract buildings + stops → accessibility → gaps
    // ==========================================================================

    /** Measures transit accessibility by computing walk-distance bands and detecting coverage gaps. */
    workflow TransitAccessibility(
        gtfs_url: String,
        region: String = "Liechtenstein"
    ) => (
        pct_within_400m: Double,
        pct_within_800m: Double,
        coverage_pct: Double,
        gap_cells: Long,
        accessibility_path: String,
        coverage_path: String
    ) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        f = TransitAccessibilityFromCache(cache = cache.cache, gtfs_url = $.gtfs_url)
        yield TransitAccessibility(
            pct_within_400m = f.pct_within_400m,
            pct_within_800m = f.pct_within_800m,
            coverage_pct = f.coverage_pct,
            gap_cells = f.gap_cells,
            accessibility_path = f.accessibility_path,
            coverage_path = f.coverage_path
        )
    }

    /** Cache-dependent logic for TransitAccessibility. */
    facet TransitAccessibilityFromCache(cache: OSMCache, gtfs_url: String) => (
        pct_within_400m: Double,
        pct_within_800m: Double,
        coverage_pct: Double,
        gap_cells: Long,
        accessibility_path: String,
        coverage_path: String
    ) andThen {
        dl = osm.Transit.GTFS.DownloadFeed(url = $.gtfs_url)
        buildings = osm.Buildings.ExtractBuildings(cache = $.cache)
        stops = osm.Transit.GTFS.ExtractStops(feed = dl.feed)
        access = osm.Transit.GTFS.StopAccessibility(
            osm_geojson_path = buildings.result.output_path,
            stops_geojson_path = stops.result.output_path,
            walk_threshold_m = 400
        )
        gaps = osm.Transit.GTFS.CoverageGaps(
            stops_geojson_path = stops.result.output_path,
            osm_geojson_path = buildings.result.output_path,
            cell_size_m = 500
        )
        yield TransitAccessibilityFromCache(
            pct_within_400m = access.result.pct_within_400m,
            pct_within_800m = access.result.pct_within_800m,
            coverage_pct = gaps.result.coverage_pct,
            gap_cells = gaps.result.gap_cells,
            accessibility_path = access.result.output_path,
            coverage_path = gaps.result.output_path
        )
    }

    // ==========================================================================
    // PATTERN 15: Low-Zoom Road Infrastructure Builder
    // Cache → Build GraphHopper → Build Zoom Layers (minZoom per edge z2–z7)
    // ==========================================================================

    /** Builds a routing graph and assigns minimum zoom levels to road edges for low-zoom tile rendering. */
    workflow RoadZoomBuilder(
        region: String = "Liechtenstein",
        output_dir: String = "/Volumes/afl_data/output/osm/zoom-builder",
        max_concurrent: Long = 16
    ) => (
        total_edges: Long,
        selected_edges: Long,
        zoom_distribution: String,
        csv_path: String,
        metrics_path: String
    ) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        f = RoadZoomBuilderFromCache(cache = cache.cache, output_dir = $.output_dir, max_concurrent = $.max_concurrent)
        yield RoadZoomBuilder(
            total_edges = f.total_edges,
            selected_edges = f.selected_edges,
            zoom_distribution = f.zoom_distribution,
            csv_path = f.csv_path,
            metrics_path = f.metrics_path
        )
    }

    /** Cache-dependent logic for RoadZoomBuilder. */
    facet RoadZoomBuilderFromCache(cache: OSMCache, output_dir: String = "/Volumes/afl_data/output/osm/zoom-builder", max_concurrent: Long = 16) => (
        total_edges: Long,
        selected_edges: Long,
        zoom_distribution: String,
        csv_path: String,
        metrics_path: String
    ) andThen {
        graph = osm.ops.GraphHopper.BuildGraph(cache = $.cache)
        zoom = osm.Roads.ZoomBuilder.BuildZoomLayers(
            cache = $.cache,
            graph = graph.graph,
            output_dir = $.output_dir,
            max_concurrent = $.max_concurrent
        )
        yield RoadZoomBuilderFromCache(
            total_edges = zoom.result.total_logical_edges,
            selected_edges = zoom.result.selected_edges,
            zoom_distribution = zoom.result.zoom_distribution,
            csv_path = zoom.result.csv_path,
            metrics_path = zoom.result.metrics_path
        )
    }
}


// OSM MongoDB import facets — import GeoJSON extractor output into MongoDB
// with 2dsphere spatial indexing for geospatial queries.

/** MongoDB geospatial import for OSM GeoJSON extractor output. */
namespace osm.db {

    /** Result of importing a GeoJSON dataset into MongoDB. */
    schema ImportResult {
        imported_count: Long,
        dataset_key: String,
        collection: String
    }

    /** Import a GeoJSON FeatureCollection into MongoDB osm_features collection. */
    event facet ImportGeoJSON(
        output_path: String,
        category: String,
        region: String,
        feature_count: Long
    ) => (
        imported_count: Long,
        dataset_key: String,
        collection: String
    )
}


// OSM filtering facets
//
// Radius-based filtering converts polygon boundaries to equivalent circular radius:
//   radius = sqrt(area / π)
//
// Type/tag filtering supports OSM element types (node, way, relation) and tags.
// Optional dependency inclusion provides complete geometries for ways/relations.

/** Spatial and tag-based filtering of OSM features by radius, type, and element tags. */
namespace osm.Filters {
    use osm.types

    /** Filtered GeoJSON output with feature counts and applied filter metadata. */
    schema FilteredFeatures {
        output_path: String,
        feature_count: Long,
        original_count: Long,
        boundary_type: String,
        filter_applied: String,
        format: String,
        extraction_date: String
    }

    /** Filtered OSM output including dependency resolution metadata. */
    schema OSMFilteredFeatures {
        output_path: String,
        feature_count: Long,
        original_count: Long,
        osm_type: String,
        filter_applied: String,
        dependencies_included: Boolean,
        dependency_count: Long,
        format: String,
        extraction_date: String
    }

    /** Filters GeoJSON features by equivalent circular radius with comparison operator. */
    event facet FilterByRadius(input_path: String, radius: Double,
        unit: String = "kilometers", operator: String = "gte") => (result: FilteredFeatures)

    /** Filters GeoJSON features by inclusive radius range. */
    event facet FilterByRadiusRange(input_path: String, min_radius: Double,
        max_radius: Double, unit: String = "kilometers") => (result: FilteredFeatures)

    /** Filters GeoJSON features by boundary type combined with radius threshold. */
    event facet FilterByTypeAndRadius(input_path: String, boundary_type: String,
        radius: Double, unit: String = "kilometers", operator: String = "gte") => (result: FilteredFeatures)

    /** Extracts boundaries from PBF and filters by radius in a single operation. */
    event facet ExtractAndFilterByRadius(cache: OSMCache, admin_levels: [Long],
        natural_types: [String], radius: Double, unit: String = "kilometers",
        operator: String = "gte") => (result: FilteredFeatures)

    /** Filters PBF by OSM element type (node, way, relation) with optional dependency inclusion. */
    event facet FilterByOSMType(input_path: String, osm_type: String,
        include_dependencies: Boolean = false) => (result: OSMFilteredFeatures)

    /** Filters PBF by OSM tag key/value pair, optionally restricted to an element type. */
    event facet FilterByOSMTag(input_path: String, tag_key: String,
        tag_value: String = "*", osm_type: String = "*",
        include_dependencies: Boolean = false) => (result: OSMFilteredFeatures)

    /** Filters pre-extracted GeoJSON by OSM type stored in feature properties. */
    event facet FilterGeoJSONByOSMType(input_path: String, osm_type: String,
        tag_key: String = "", tag_value: String = "*") => (result: OSMFilteredFeatures)
}


// OSMOSE Local Verifier
//
// Standalone local PBF/GeoJSON quality analysis — no network dependency.
// Runs deep verification directly on .osm.pbf files (from GeoFabrik, via
// OSMCache) and GeoJSON files.  Single-pass processing checks reference
// integrity, coordinate ranges, geometry validity, tag completeness, and
// duplicate IDs.
//
// Severity levels:
//   1 (error)   — reference integrity failures, out-of-bounds coords,
//                  degenerate geometry, duplicate IDs
//   2 (warning) — missing name on named features, unclosed polygons
//   3 (info)    — empty tag values

/** Standalone local PBF/GeoJSON quality analysis with severity-graded issue detection. */
namespace osm.ops.OSMOSE {

    use osm.types

    /** Verification output file with element counts. */
    schema VerifyResult {
        output_path: String,
        issue_count: Long,
        node_count: Long,
        way_count: Long,
        relation_count: Long,
        format: String,
        verify_date: String
    }

    /** Aggregate issue counts by category and severity level. */
    schema VerifySummary {
        total_issues: Long,
        geometry_issues: Long,
        tag_issues: Long,
        reference_issues: Long,
        coordinate_issues: Long,
        duplicate_issues: Long,
        level_1: Long,
        level_2: Long,
        level_3: Long,
        tag_coverage_pct: Double,
        avg_tags_per_element: Double,
        verify_date: String
    }

    /** Runs all verification checks on a PBF cache. */
    event facet VerifyAll(
        cache: OSMCache,
        output_dir: String = "/Volumes/afl_data/output/osm/osmose",
        check_geometry: Boolean = true,
        check_tags: Boolean = true,
        check_references: Boolean = true,
        check_coordinates: Boolean = true,
        check_duplicates: Boolean = true
    ) => (result: VerifyResult, summary: VerifySummary)

    /** Verifies geometry only (degenerate ways, unclosed polygons). */
    event facet VerifyGeometry(
        cache: OSMCache
    ) => (result: VerifyResult, summary: VerifySummary)

    /** Verifies tag completeness with optional required-tag list. */
    event facet VerifyTags(
        cache: OSMCache,
        required_tags: String = "name"
    ) => (result: VerifyResult, summary: VerifySummary)

    /** Verifies an existing GeoJSON file for structure, geometry, and coordinates. */
    event facet VerifyGeoJSON(
        input_path: String
    ) => (result: VerifyResult, summary: VerifySummary)

    /** Reads verification output and computes aggregate statistics. */
    event facet ComputeVerifySummary(
        input_path: String
    ) => (summary: VerifySummary)
}


// OSM Cache Validation
//
// Validates OSM cache entries for data quality:
// - Missing required tags (name, type)
// - Invalid or degenerate geometry
// - Coordinates outside valid ranges
// - Duplicate node/way IDs
//
// Produces good/bad statistics and writes invalid entries to output file.

/** OSM data quality validation: tag completeness, geometry, bounds, and duplicates. */
namespace osm.ops.Validation {
    use osm.types

    /** Validation summary with counts by error category. */
    schema ValidationStats {
        total_entries: Long,
        valid_entries: Long,
        invalid_entries: Long,
        missing_tags: Long,
        invalid_geometry: Long,
        out_of_bounds: Long,
        duplicate_entries: Long,
        validation_date: String
    }

    /** Output file containing invalid entries. */
    schema ValidationResult {
        output_path: String,
        feature_count: Long,
        format: String,
        validation_date: String
    }

    /** Runs all validation checks on a cached OSM dataset. */
    event facet ValidateCache(cache: OSMCache,
        output_dir: String = "/Volumes/afl_data/output/osm/validation",
        use_hdfs: Boolean = false) => (stats: ValidationStats, result: ValidationResult)

    /** Validates geometry correctness only. */
    event facet ValidateGeometry(cache: OSMCache) => (stats: ValidationStats, result: ValidationResult)

    /** Validates tag completeness against required tags. */
    event facet ValidateTags(cache: OSMCache,
        required_tags: String = "name") => (stats: ValidationStats, result: ValidationResult)

    /** Validates coordinate bounds against a bounding box. */
    event facet ValidateBounds(cache: OSMCache,
        min_lat: Double = -90.0,
        max_lat: Double = 90.0,
        min_lon: Double = -180.0,
        max_lon: Double = 180.0) => (stats: ValidationStats, result: ValidationResult)

    /** Reads a validation result file and computes summary statistics. */
    event facet ValidationSummary(input_path: String) => (stats: ValidationStats)
}


// GraphHopper routing graph operations
// Takes OSM cache as input and builds routing graphs

/** GraphHopper routing graph construction and management. */
namespace osm.ops.GraphHopper {
    use osm.types

    /** Builds a routing graph for a profile, returning cached graph if available. */
    event facet BuildGraph(cache: OSMCache, profile: String = "car", recreate: Boolean = false) => (graph: GraphHopperCache)

    /** Builds routing graphs for multiple profiles simultaneously. */
    event facet BuildMultiProfile(cache: OSMCache, profiles: [String], recreate: Boolean = false) => (graphs: [GraphHopperCache])

    /** Builds a routing graph in bulk batch mode. */
    event facet BuildGraphBatch(cache: OSMCache, profile: String = "car", recreate: Boolean = false) => (graph: GraphHopperCache)

    /** Imports an existing routing graph, building it if not found. */
    event facet ImportGraph(cache: OSMCache, profile: String = "car", recreate: Boolean = false) => (graph: GraphHopperCache)

    /** Validates a routing graph and returns node/edge statistics. */
    event facet ValidateGraph(graph: GraphHopperCache) => (valid: Boolean, nodeCount: Long, edgeCount: Long)

    /** Deletes a routing graph directory. */
    event facet CleanGraph(graph: GraphHopperCache) => (deleted: Boolean)
}


// GraphHopper workflow compositions
// Builds routing graphs from OSM caches for entire regions

/** Batch GraphHopper routing graph construction for European countries. */
namespace osm.GraphHopper.Europe {
    use osm.types
    uses osm.cache.Europe
    uses osm.cache.GraphHopper.Europe

    /** Builds routing graphs for ten major European countries in parallel. */
    workflow BuildMajorEuropeGraphs(profile: String = "car", recreate: Boolean = false) => (graphs: [GraphHopperCache]) andThen {

        // Step 1: Get OSM caches (parallel)
        germany_osm = osm.cache.Europe.Germany()
        france_osm = osm.cache.Europe.France()
        spain_osm = osm.cache.Europe.Spain()
        italy_osm = osm.cache.Europe.Italy()
        uk_osm = osm.cache.Europe.UnitedKingdom()
        poland_osm = osm.cache.Europe.Poland()
        netherlands_osm = osm.cache.Europe.Netherlands()
        belgium_osm = osm.cache.Europe.Belgium()
        austria_osm = osm.cache.Europe.Austria()
        switzerland_osm = osm.cache.Europe.Switzerland()

        // Step 2: Build routing graphs (parallel)
        germany_gh = osm.cache.GraphHopper.Europe.Germany(cache = germany_osm.cache, profile = $.profile, recreate = $.recreate)
        france_gh = osm.cache.GraphHopper.Europe.France(cache = france_osm.cache, profile = $.profile, recreate = $.recreate)
        spain_gh = osm.cache.GraphHopper.Europe.Spain(cache = spain_osm.cache, profile = $.profile, recreate = $.recreate)
        italy_gh = osm.cache.GraphHopper.Europe.Italy(cache = italy_osm.cache, profile = $.profile, recreate = $.recreate)
        uk_gh = osm.cache.GraphHopper.Europe.UnitedKingdom(cache = uk_osm.cache, profile = $.profile, recreate = $.recreate)
        poland_gh = osm.cache.GraphHopper.Europe.Poland(cache = poland_osm.cache, profile = $.profile, recreate = $.recreate)
        netherlands_gh = osm.cache.GraphHopper.Europe.Netherlands(cache = netherlands_osm.cache, profile = $.profile, recreate = $.recreate)
        belgium_gh = osm.cache.GraphHopper.Europe.Belgium(cache = belgium_osm.cache, profile = $.profile, recreate = $.recreate)
        austria_gh = osm.cache.GraphHopper.Europe.Austria(cache = austria_osm.cache, profile = $.profile, recreate = $.recreate)
        switzerland_gh = osm.cache.GraphHopper.Europe.Switzerland(cache = switzerland_osm.cache, profile = $.profile, recreate = $.recreate)

        // Step 3: Aggregate results
        yield BuildMajorEuropeGraphs(graphs = germany_gh.graph ++ france_gh.graph ++ spain_gh.graph ++ italy_gh.graph ++ uk_gh.graph ++ poland_gh.graph ++ netherlands_gh.graph ++ belgium_gh.graph ++ austria_gh.graph ++ switzerland_gh.graph)
    }

