// National and State Parks extraction from OSM data
//
// Extracts park boundaries and protected areas with classification:
// - National parks (boundary=national_park, protect_class=2)
// - State/regional parks (protect_class=5)
// - Nature reserves (leisure=nature_reserve)
// - All protected areas (boundary=protected_area)

/** National parks, state parks, nature reserves, and protected area extraction. */
namespace osm.Parks {
    use osm.types

    /** Extracted park data with protection class and total area. */
    schema ParkFeatures {
        output_path: String,
        feature_count: Long,
        park_type: String,
        protect_classes: String,
        total_area_km2: Double,
        format: String,
        extraction_date: String
    }

    /** Aggregate park statistics by category. */
    schema ParkStats {
        total_parks: Long,
        total_area_km2: Double,
        national_parks: Long,
        state_parks: Long,
        nature_reserves: Long,
        other_protected: Long,
        park_type: String
    }

    /** Individual park feature with designation and operator details. */
    schema ParkFeature {
        osm_id: Long,
        name: String,
        park_type: String,
        protect_class: String,
        designation: String,
        operator: String,
        area_km2: Double
    }

    /** Extracts national parks (boundary=national_park or protect_class=2). */
    event facet NationalParks(cache: OSMCache) => (result: ParkFeatures)

    /** Extracts state and regional parks (protect_class=5). */
    event facet StateParks(cache: OSMCache) => (result: ParkFeatures)

    /** Extracts nature reserves (leisure=nature_reserve). */
    event facet NatureReserves(cache: OSMCache) => (result: ParkFeatures)

    /** Extracts all protected areas, optionally filtered by protect_class. */
    event facet ProtectedAreas(cache: OSMCache,
        protect_classes: String = "*") => (result: ParkFeatures)

    /** Extracts parks by configurable type and protection class. */
    event facet ExtractParks(cache: OSMCache, park_type: String = "all",
        protect_classes: String = "*") => (result: ParkFeatures)

    /** Filters pre-extracted GeoJSON by park type. */
    event facet FilterParksByType(input_path: String, park_type: String,
        protect_classes: String = "*") => (result: ParkFeatures)

    /** Computes aggregate park statistics. */
    event facet ParkStatistics(input_path: String) => (stats: ParkStats)

    /** Extracts parks above a minimum area threshold. */
    event facet LargeParks(cache: OSMCache, min_area_km2: Double = 100,
        park_type: String = "all") => (result: ParkFeatures)
}


/** Points of interest extraction from OSM data: settlements, landmarks, and facilities. */
namespace osm.POIs {
    use osm.types

    /** Extracts all points of interest from cached OSM data. */
    event facet POI(cache: OSMCache) => (pois: OSMCache )

    /** Filters volcanoes by elevation and active status. */
    facet Volcanos(cache: OSMCache, elevation:Long, active:Boolean) => (pois: OSMCache )
    /** Filters prisons by operator, capacity, security level, and gender. */
    facet Prisons(operator:String, capacity:Long, securityLevel:String, gender:String ) => (pois: OSMCache )
    /** Extracts national park POIs. */
    facet NationalParks() => (pois: OSMCache )
    /** Extracts state park POIs. */
    facet StateParks() => (pois: OSMCache )
    /** Extracts hospital POIs. */
    facet Hospitals() => (pois: OSMCache )
    /** Extracts airport POIs. */
    facet Airports() => (pois: OSMCache )
    /** Extracts military installation POIs by kind. */
    facet Military(kind:String) => (pois: OSMCache )

    /** Extracts city-level settlements. */
    event facet Cities(cache: OSMCache) => (cities: OSMCache )
    /** Extracts town-level settlements. */
    event facet Towns(cache: OSMCache) => (towns: OSMCache )
    /** Extracts suburb-level settlements. */
    event facet Suburbs(cache: OSMCache) => (towns: OSMCache )
    /** Extracts village-level settlements. */
    event facet Villages(cache: OSMCache) => (villages: OSMCache )
    /** Extracts hamlet-level settlements. */
    event facet Hamlets(cache: OSMCache) => (villages: OSMCache )
    /** Extracts country-level boundaries. */
    event facet Countries(cache: OSMCache) => (villages: OSMCache )
    /** Converts cached OSM data to GeoJSON format. */
    event facet GeoOSMCache(cache: OSMCache) => (geojson: OSMCache )

}






// Population-based filtering for OSM data
//
// Filters places and administrative boundaries by population.
// Supports cities, towns, villages, states, countries, counties, etc.

/** Population-based filtering for cities, towns, villages, and administrative areas. */
namespace osm.Population {
    use osm.types

    /** Filtered result with population thresholds and place type metadata. */
    schema PopulationFilteredFeatures {
        output_path: String,
        feature_count: Long,
        original_count: Long,
        place_type: String,
        min_population: Long,
        max_population: Long,
        filter_applied: String,
        format: String,
        extraction_date: String
    }

    /** Aggregate population statistics for a set of places. */
    schema PopulationStats {
        total_places: Long,
        total_population: Long,
        min_population: Long,
        max_population: Long,
        avg_population: Long,
        place_type: String
    }

    /** Filters GeoJSON features by population threshold and place type. */
    event facet FilterByPopulation(input_path: String, min_population: Long,
        place_type: String = "all", operator: String = "gte") => (result: PopulationFilteredFeatures)

    /** Filters GeoJSON features by inclusive population range. */
    event facet FilterByPopulationRange(input_path: String, min_population: Long,
        max_population: Long, place_type: String = "all") => (result: PopulationFilteredFeatures)

    /** Extracts places with population tags from PBF, filtered by type and minimum. */
    event facet ExtractPlacesWithPopulation(cache: OSMCache, place_type: String = "all",
        min_population: Long = 0) => (result: PopulationFilteredFeatures)

    /** Computes population statistics for a GeoJSON file. */
    event facet PopulationStatistics(input_path: String,
        place_type: String = "all") => (stats: PopulationStats)

    /** Extracts cities (place=city) with population data. */
    event facet Cities(cache: OSMCache, min_population: Long = 0) => (result: PopulationFilteredFeatures)

    /** Extracts towns (place=town) with population data. */
    event facet Towns(cache: OSMCache, min_population: Long = 0) => (result: PopulationFilteredFeatures)

    /** Extracts villages (place=village) with population data. */
    event facet Villages(cache: OSMCache, min_population: Long = 0) => (result: PopulationFilteredFeatures)

    /** Extracts countries (admin_level=2) with population data. */
    event facet Countries(cache: OSMCache) => (result: PopulationFilteredFeatures)

    /** Extracts states and provinces (admin_level=4) with population data. */
    event facet States(cache: OSMCache) => (result: PopulationFilteredFeatures)

    /** Extracts counties (admin_level=6) with population data. */
    event facet Counties(cache: OSMCache) => (result: PopulationFilteredFeatures)

    /** Extracts all places that have a population tag. */
    event facet AllPopulatedPlaces(cache: OSMCache, min_population: Long = 0) => (result: PopulationFilteredFeatures)
}


