    event facet FilterBySpeedLimit(input_path: String,
        min_speed: Long, max_speed: Long) => (result: RoadFeatures)
}


// Low-Zoom Road Infrastructure Builder (Zoom 2–7)
//
// Offline pipeline that produces minZoom per logical edge (plus bypass/ring/backbone
// flags) for progressive map rendering at zoom levels 2–7.
//
// Pipeline: build logical edge graph from PBF → compute structural betweenness
// via sampled routing → apply adaptive cell budgets → detect bypasses/rings
// → enforce monotonic reveal → export.

/** Low-zoom road infrastructure builder for progressive map rendering at zoom levels 2-7. */
namespace osm.Roads.ZoomBuilder {
    use osm.types

    /** Merged road segment between decision nodes with classification attributes. */
    schema LogicalEdge {
        edgeId: String,
        fromNode: String,
        toNode: String,
        osmWayIds: String,
        lengthM: Double,
        fc: String,
        fcScore: Double,
        ref: String,
        name: String,
        maxspeed: Long,
        lanes: Long,
        bridge: Boolean,
        tunnel: Boolean,
        oneway: Boolean,
        surfaceUnpaved: Boolean
    }

    /** Per-edge output with zoom scores and structural flags. */
    schema ZoomEdgeResult {
        edgeId: String,
        fromNode: String,
        toNode: String,
        osmWayIds: String,
        lengthM: Double,
        fc: String,
        minZoom: Long,
        scores_csv: String,
        sb_csv: String,
        backbone: Boolean,
        isBypass: Boolean,
        isRing: Boolean,
        isLegacyThruTown: Boolean,
        isBridgeOrTunnel: Boolean
    }

    /** Top-level pipeline result with zoom distribution and output paths. */
    schema ZoomBuilderResult {
        output_dir: String,
        total_logical_edges: Long,
        selected_edges: Long,
        zoom_distribution: String,
        city_count: Long,
        pair_count: Long,
        route_count: Long,
        csv_path: String,
        metrics_path: String,
        format: String,
        extraction_date: String
    }

    /** Pipeline diagnostics with edge counts and timing. */
    schema ZoomBuilderMetrics {
        total_logical_edges: Long,
        selected_edges: Long,
        pruned_edges: Long,
        backbone_edges: Long,
        bypass_edges: Long,
        ring_edges: Long,
        city_count: Long,
        anchor_counts: String,
        pair_counts: String,
        route_count: Long,
        zoom_distribution: String,
        budget_utilization: String,
        processing_seconds: Double
    }

    /** Tunable parameters for the zoom builder pipeline. */
    schema ZoomBuilderConfig {
        min_zoom: Long,
        max_zoom: Long,
        max_concurrent_routes: Long,
        bypass_time_ratio: Double,
        ring_cv_threshold: Double,
        hair_max_length_km: Double
    }

    /** Per-cell budget allocation with density factor. */
    schema CellBudget {
        cell_id: String,
        zoom: Long,
        budget_km: Double,
        used_km: Double,
        density_factor: Double
    }

    /** Builds a logical edge graph from PBF data. */
    event facet BuildLogicalGraph(cache: OSMCache) => (
        edge_count: Long,
        node_count: Long,
        graph_path: String
    )

    /** Builds anchor node sets for a given zoom level. */
    event facet BuildAnchors(
        graph_path: String,
        cities_path: String,
        zoom_level: Long
    ) => (
        anchors_path: String,
        anchor_count: Long
    )

    /** Computes structural betweenness sampling for a zoom level. */
    event facet ComputeSBS(
        graph_path: String,
        anchors_path: String,
        graph: GraphHopperCache,
        zoom_level: Long,
        k_pairs: Long = 5000
    ) => (
        sbs_path: String,
        route_count: Long
    )

    /** Computes per-zoom scores from SBS data. */
    event facet ComputeScores(
        graph_path: String,
        sbs_paths: String
    ) => (
        scores_path: String
    )

    /** Detects bypass roads around settlements. */
    event facet DetectBypasses(
        graph_path: String,
        cities_path: String,
        graph: GraphHopperCache
    ) => (
        bypasses_path: String,
        bypass_count: Long
    )

    /** Detects ring roads around large settlements. */
    event facet DetectRings(
        graph_path: String,
        cities_path: String,
        graph: GraphHopperCache
    ) => (
        rings_path: String,
        ring_count: Long
    )

    /** Selects edges with budgeted greedy selection and backbone repair. */
    event facet SelectEdges(
        graph_path: String,
        scores_path: String,
        cities_path: String,
        bypasses_path: String = "",
        rings_path: String = ""
    ) => (
        assignments_path: String,
        selected_count: Long
    )

    /** Exports final zoom layer assignments. */
    event facet ExportZoomLayers(
        assignments_path: String,
        graph_path: String,
        output_dir: String
    ) => (
        result: ZoomBuilderResult
    )

    /** Orchestrates the full zoom builder pipeline end-to-end. */
    event facet BuildZoomLayers(
        cache: OSMCache,
        graph: GraphHopperCache,
        min_population: Long = 50000,
        output_dir: String = "/Volumes/afl_data/output/osm/zoom-builder",
        max_concurrent: Long = 16
    ) => (
        result: ZoomBuilderResult,
        metrics: ZoomBuilderMetrics
    )
}


// Pairwise city-routing event facet.
//
// The all-pairs shortest-path routing primitive used by the city-routing
// workflows (see handlers/routing/ffl/routing_workflows.ffl). The handler
// is osm.Routing.ComputePairwiseRoutes in handlers/routes/routing_handlers.py.
//
// Prerequisites: compile with osmtypes.ffl (defines osm.types.RoutingTopology).
//
// (The former osm.CityRouting.CityRouteMap pipeline that lived here depended
// on osm.ops.PgRouting / DownloadPBF / BuildRoutingTopology / ValidateTopology
// handlers that no longer exist — it was removed; the live city-routing
// workflows are in routing_workflows.ffl.)

/** Pairwise driving-route computation between cities. */
namespace osm.Routing {
    use osm.types

    /** Aggregate result of all-pairs shortest-path routing between cities. */
    schema PairwiseRoutingResult {
        output_path: String,
        route_count: Long,
        city_count: Long,
        total_distance_km: Long,
        total_duration_min: Long,
        avg_distance_km: Long,
        avg_duration_min: Long,
        profile: String,
        format: String
    }

    /** Computes all-pairs shortest-path routes between cities and returns LineString geometries. */
    event facet ComputePairwiseRoutes(
        cities_path: String,
        topology: RoutingTopology
    ) => (result: PairwiseRoutingResult)
}


// OSM Elevation enrichment and filtering
//
// Enriches route geometries with elevation data from DEM sources
// and provides filtering by elevation criteria.
//
// Elevation sources:
// - "srtm": NASA SRTM 30m resolution (default, via Open-Elevation API)
// - "mapbox": Mapbox Terrain-RGB (requires API key)
//
// All elevations are in feet unless otherwise specified.

/** Elevation enrichment and filtering using DEM data (SRTM, Mapbox). */
namespace osm.Elevation {
    use osm.types

    /** Elevation statistics for a route or area in feet. */
    schema ElevationStats {
        min_elevation_ft: Long,
        max_elevation_ft: Long,
        elevation_gain_ft: Long,
        elevation_loss_ft: Long,
        avg_elevation_ft: Long,
        points_sampled: Long
    }

    /** Route enriched with elevation profile and statistics. */
    schema ElevatedRoute {
        route_id: String,
        name: String,
        route_type: String,
        network: String,
        geometry: Json,
        elevation_profile: Json,
        stats: ElevationStats
    }

    /** Batch result of elevation-enriched routes with filter metadata. */
    schema ElevatedRouteFeatures {
        output_path: String,
        routes: Json,
        feature_count: Long,
        matched_count: Long,
        filter_applied: String,
        elevation_source: String,
        extraction_date: String
    }

    /** Enriches GeoJSON routes with elevation data by sampling each vertex. */
    event facet EnrichWithElevation(input_path: String,
        dem_source: String = "srtm",
        sample_interval_m: Long = 100) => (result: ElevatedRouteFeatures)

    /** Filters routes where max elevation exceeds a threshold. */
    event facet FilterByMaxElevation(input_path: String,
        min_max_elevation_ft: Long) => (result: ElevatedRouteFeatures)

    /** Filters routes where min elevation is below a threshold. */
    event facet FilterByMinElevation(input_path: String,
        max_min_elevation_ft: Long) => (result: ElevatedRouteFeatures)

    /** Filters routes by minimum total elevation gain. */
    event facet FilterByElevationGain(input_path: String,
        min_gain_ft: Long) => (result: ElevatedRouteFeatures)

    /** Filters routes that have points within an elevation range. */
    event facet FilterByElevationRange(input_path: String,
        min_elevation_ft: Long,
        max_elevation_ft: Long) => (result: ElevatedRouteFeatures)

    /** Extracts hiking trails above a minimum elevation. */
    event facet HighElevationHikingTrails(cache: OSMCache,
        min_elevation_ft: Long = 2000,
        network: String = "*",
        dem_source: String = "srtm") => (result: ElevatedRouteFeatures)

    /** Extracts cycling routes above a minimum elevation. */
    event facet HighElevationCyclingRoutes(cache: OSMCache,
        min_elevation_ft: Long = 2000,
        network: String = "*",
        dem_source: String = "srtm") => (result: ElevatedRouteFeatures)

    /** Extracts routes of any type above a minimum elevation. */
    event facet HighElevationRoutes(cache: OSMCache,
        route_type: String,
        min_elevation_ft: Long = 2000,
        network: String = "*",
        dem_source: String = "srtm") => (result: ElevatedRouteFeatures)

    /** Extracts routes with significant elevation gain for climbing. */
    event facet ClimbingRoutes(cache: OSMCache,
        route_type: String,
        min_gain_ft: Long = 1000,
        network: String = "*",
        dem_source: String = "srtm") => (result: ElevatedRouteFeatures)
}


// Composed elevation + map workflows
//
// Full pipeline workflows that extract routes, enrich with elevation data,
// filter by elevation criteria, and render interactive maps.
//
// Prerequisites: Compile with osmtypes.afl, osmroutes.afl, osmelevation.afl, osmvisualization.afl

/** End-to-end pipelines that extract routes, enrich with SRTM elevation data, filter, and render maps. */
namespace osm.ElevationMap {
    use osm.types
    use osm.Routes
    use osm.Elevation
    use osm.viz

    /** Filters bicycle routes by peak elevation and renders the survivors on an interactive map. */
    workflow BicycleElevationMap(
        cache: OSMCache,
        min_elevation_ft: Long = 4000,
        network: String = "*",
        title: String = "High Elevation Cycling Routes",
        color: String = "#e74c3c"
    ) => (map_path: String, feature_count: Long, matched_count: Long) andThen {
        // Extract bicycle routes from OSM data
        routes = BicycleRoutes(cache = $.cache, network = $.network)

        // Enrich route geometries with elevation data from SRTM
        enriched = EnrichWithElevation(input_path = routes.result.output_path)

        // Keep only routes that reach above the elevation threshold
        filtered = FilterByMaxElevation(
            input_path = enriched.result.output_path,
            min_max_elevation_ft = $.min_elevation_ft
        )

        // Render the filtered routes on an interactive Leaflet map
        map = RenderMap(
            geojson_path = filtered.result.output_path,
            title = $.title,
            color = $.color
        )

        yield BicycleElevationMap(
            map_path = map.result.output_path,
            feature_count = filtered.result.feature_count,
            matched_count = filtered.result.matched_count
        )
    }

    /** Filters hiking trails by peak elevation and renders them on an interactive map. */
    workflow HikingElevationMap(
        cache: OSMCache,
        min_elevation_ft: Long = 2000,
        network: String = "*",
        title: String = "High Elevation Hiking Trails",
        color: String = "#e67e22"
    ) => (map_path: String, feature_count: Long, matched_count: Long) andThen {
        trails = HikingTrails(cache = $.cache, network = $.network)
        enriched = EnrichWithElevation(input_path = trails.result.output_path)
        filtered = FilterByMaxElevation(
            input_path = enriched.result.output_path,
            min_max_elevation_ft = $.min_elevation_ft
        )
        map = RenderMap(
            geojson_path = filtered.result.output_path,
            title = $.title,
            color = $.color
        )
        yield HikingElevationMap(
            map_path = map.result.output_path,
            feature_count = filtered.result.feature_count,
            matched_count = filtered.result.matched_count
        )
    }

    /** Generic elevation map: accepts any route type, filters by peak elevation, and renders. */
    workflow ElevationRouteMap(
        cache: OSMCache,
        route_type: String,
        min_elevation_ft: Long = 2000,
        network: String = "*",
        title: String = "High Elevation Routes",
        color: String = "#3498db"
    ) => (map_path: String, feature_count: Long, matched_count: Long) andThen {
        routes = osm.Routes.ExtractRoutes(
            cache = $.cache,
            route_type = $.route_type,
            network = $.network
        )
        enriched = EnrichWithElevation(input_path = routes.result.output_path)
        filtered = FilterByMaxElevation(
            input_path = enriched.result.output_path,
            min_max_elevation_ft = $.min_elevation_ft
        )
        map = RenderMap(
            geojson_path = filtered.result.output_path,
            title = $.title,
            color = $.color
        )
        yield ElevationRouteMap(
            map_path = map.result.output_path,
            feature_count = filtered.result.feature_count,
            matched_count = filtered.result.matched_count
        )
    }

    /** Selects routes with significant elevation gain and renders them on an interactive map. */
    workflow ClimbingRoutesMap(
        cache: OSMCache,
        route_type: String = "bicycle",
        min_gain_ft: Long = 1000,
        network: String = "*",
        title: String = "Climbing Routes",
        color: String = "#9b59b6"
    ) => (map_path: String, feature_count: Long, matched_count: Long) andThen {
        routes = osm.Routes.ExtractRoutes(
            cache = $.cache,
            route_type = $.route_type,
            network = $.network
        )
        enriched = EnrichWithElevation(input_path = routes.result.output_path)
        filtered = FilterByElevationGain(
            input_path = enriched.result.output_path,
            min_gain_ft = $.min_gain_ft
        )
        map = RenderMap(
            geojson_path = filtered.result.output_path,
            title = $.title,
            color = $.color
        )
        yield ClimbingRoutesMap(
            map_path = map.result.output_path,
            feature_count = filtered.result.feature_count,
            matched_count = filtered.result.matched_count
        )
    }

    /** Full five-stage pipeline: bicycle routes, elevation enrichment, filter, statistics, and map. */
    workflow BicycleElevationStatsMap(
        cache: OSMCache,
        min_elevation_ft: Long = 4000,
        network: String = "*",
        title: String = "High Elevation Cycling Routes",
        color: String = "#e74c3c"
    ) => (map_path: String, feature_count: Long, matched_count: Long, route_count: Long, total_length_km: Double) andThen {
        routes = BicycleRoutes(cache = $.cache, network = $.network)
        enriched = EnrichWithElevation(input_path = routes.result.output_path)
        filtered = FilterByMaxElevation(
            input_path = enriched.result.output_path,
            min_max_elevation_ft = $.min_elevation_ft
        )

        // Compute statistics on the filtered routes
        stats = RouteStatistics(input_path = filtered.result.output_path)

        map = RenderMap(
            geojson_path = filtered.result.output_path,
            title = $.title,
            color = $.color
        )

        yield BicycleElevationStatsMap(
            map_path = map.result.output_path,
            feature_count = filtered.result.feature_count,
            matched_count = filtered.result.matched_count,
            route_count = stats.stats.route_count,
            total_length_km = stats.stats.total_length_km
        )
    }
}


// Region-based elevation workflow wrappers
//
// Accept a human-friendly region name, resolve to a typed Region, download
// the PBF, then run each osm.Elevation.Workflows.* workflow with the
// resulting cache.

/** Region-name-driven wrappers for all elevation workflows. */
namespace osm.Elevation.RegionWorkflows {
    use osm.types
    use osm.Region
    use osm.cache
    use osm.Elevation

    /** Resolves a region, then finds hiking trails above a given elevation. */
    workflow FindHighElevationHikingTrailsByRegion(
        region: String,
        prefer_continent: String = "",
        min_elevation_ft: Long = 2000
    ) => (result: ElevatedRouteFeatures, region_name: String) andThen {
        resolved = ResolveRegion(name = $.region, prefer_continent = $.prefer_continent)
        cached = osm.cache.Download(region = resolved.region)
        trails = osm.Elevation.Workflows.FindHighElevationHikingTrails(
            cache = cached.cache,
            min_elevation_ft = $.min_elevation_ft
        )
        yield FindHighElevationHikingTrailsByRegion(
            result = trails.result,
            region_name = resolved.region.name
        )
    }

    /** Resolves a region, then finds cycling routes above a given elevation. */
    workflow FindHighElevationCyclingRoutesByRegion(
        region: String,
        prefer_continent: String = "",
        min_elevation_ft: Long = 2000,
        network: String = "*"
    ) => (result: ElevatedRouteFeatures, region_name: String) andThen {
        resolved = ResolveRegion(name = $.region, prefer_continent = $.prefer_continent)
        cached = osm.cache.Download(region = resolved.region)
        routes = osm.Elevation.Workflows.FindHighElevationCyclingRoutes(
            cache = cached.cache,
            min_elevation_ft = $.min_elevation_ft,
            network = $.network
        )
        yield FindHighElevationCyclingRoutesByRegion(
            result = routes.result,
            region_name = resolved.region.name
        )
    }

    /** Resolves a region, then finds routes with significant elevation gain. */
    workflow FindClimbingRoutesByRegion(
        region: String,
        prefer_continent: String = "",
        route_type: String = "hiking",
        min_gain_ft: Long = 1000
    ) => (result: ElevatedRouteFeatures, region_name: String) andThen {
        resolved = ResolveRegion(name = $.region, prefer_continent = $.prefer_continent)
        cached = osm.cache.Download(region = resolved.region)
        climbs = osm.Elevation.Workflows.FindClimbingRoutes(
            cache = cached.cache,
            route_type = $.route_type,
            min_gain_ft = $.min_gain_ft
        )
        yield FindClimbingRoutesByRegion(
            result = climbs.result,
            region_name = resolved.region.name
        )
    }

    /** Resolves a region, then finds routes in an alpine elevation band. */
    workflow FindAlpineRoutesByRegion(
        region: String,
        prefer_continent: String = "",
        route_type: String = "hiking",
        min_elevation_ft: Long = 8000,
        max_elevation_ft: Long = 14500
    ) => (result: ElevatedRouteFeatures, region_name: String) andThen {
        resolved = ResolveRegion(name = $.region, prefer_continent = $.prefer_continent)
        cached = osm.cache.Download(region = resolved.region)
        alpine = osm.Elevation.Workflows.FindAlpineRoutes(
            cache = cached.cache,
            route_type = $.route_type,
            min_elevation_ft = $.min_elevation_ft,
            max_elevation_ft = $.max_elevation_ft
        )
        yield FindAlpineRoutesByRegion(
            result = alpine.result,
            region_name = resolved.region.name
        )
    }

    /** Resolves a region, then finds low-elevation accessible trails. */
    workflow FindLowElevationTrailsByRegion(
        region: String,
        prefer_continent: String = "",
        max_elevation_ft: Long = 500
    ) => (result: ElevatedRouteFeatures, region_name: String) andThen {
        resolved = ResolveRegion(name = $.region, prefer_continent = $.prefer_continent)
        cached = osm.cache.Download(region = resolved.region)
        low = osm.Elevation.Workflows.FindLowElevationTrails(
            cache = cached.cache,
            max_elevation_ft = $.max_elevation_ft
        )
        yield FindLowElevationTrailsByRegion(
            result = low.result,
            region_name = resolved.region.name
        )
    }
}


// Elevation-based route filtering workflows
//
// Example workflows demonstrating how to find routes based on elevation criteria.

/** Workflows that filter routes by elevation criteria such as peak height, gain, and alpine zones. */
namespace osm.Elevation.Workflows {
    use osm.types
    use osm.Routes
    use osm.Elevation

    /** Finds hiking trails whose maximum elevation exceeds a threshold (default 2000 ft). */
    workflow FindHighElevationHikingTrails(
        cache: OSMCache,
        min_elevation_ft: Long = 2000
    ) => (result: ElevatedRouteFeatures) andThen {
        // Step 1: Extract hiking trails from OSM data
        trails = HikingTrails(cache = $.cache)

        // Step 2: Enrich with elevation data
        enriched = EnrichWithElevation(input_path = trails.result.output_path)

        // Step 3: Filter by elevation threshold
        filtered = FilterByMaxElevation(
            input_path = enriched.result.output_path,
            min_max_elevation_ft = $.min_elevation_ft
        )

        yield FindHighElevationHikingTrails(result = filtered.result)
    }

    /** Finds cycling routes that reach above a given elevation threshold. */
    workflow FindHighElevationCyclingRoutes(
        cache: OSMCache,
        min_elevation_ft: Long = 2000,
        network: String = "*"
    ) => (result: ElevatedRouteFeatures) andThen {
        routes = BicycleRoutes(cache = $.cache, network = $.network)
        enriched = EnrichWithElevation(input_path = routes.result.output_path)
        filtered = FilterByMaxElevation(
            input_path = enriched.result.output_path,
            min_max_elevation_ft = $.min_elevation_ft
        )
        yield FindHighElevationCyclingRoutes(result = filtered.result)
    }

    /** Finds routes with significant total elevation gain (climbing). */
    workflow FindClimbingRoutes(
        cache: OSMCache,
        route_type: String = "hiking",
        min_gain_ft: Long = 1000
    ) => (result: ElevatedRouteFeatures) andThen {
        routes = osm.Routes.ExtractRoutes(cache = $.cache, route_type = $.route_type)
        enriched = EnrichWithElevation(input_path = routes.result.output_path)
        filtered = FilterByElevationGain(
            input_path = enriched.result.output_path,
            min_gain_ft = $.min_gain_ft
        )
        yield FindClimbingRoutes(result = filtered.result)
    }

    /** Finds routes that pass through an alpine elevation band (default 8000-14500 ft). */
    workflow FindAlpineRoutes(
        cache: OSMCache,
        route_type: String = "hiking",
        min_elevation_ft: Long = 8000,
        max_elevation_ft: Long = 14500
    ) => (result: ElevatedRouteFeatures) andThen {
        routes = osm.Routes.ExtractRoutes(cache = $.cache, route_type = $.route_type)
        enriched = EnrichWithElevation(input_path = routes.result.output_path)
        filtered = FilterByElevationRange(
            input_path = enriched.result.output_path,
            min_elevation_ft = $.min_elevation_ft,
            max_elevation_ft = $.max_elevation_ft
        )
        yield FindAlpineRoutes(result = filtered.result)
    }

    /** Finds low-elevation accessible trails that stay below a ceiling (default 500 ft). */
    workflow FindLowElevationTrails(
        cache: OSMCache,
        max_elevation_ft: Long = 500
    ) => (result: ElevatedRouteFeatures) andThen {
        trails = HikingTrails(cache = $.cache)
        enriched = EnrichWithElevation(input_path = trails.result.output_path)
        filtered = FilterByMinElevation(
            input_path = enriched.result.output_path,
            max_min_elevation_ft = $.max_elevation_ft
        )
        yield FindLowElevationTrails(result = filtered.result)
    }
}


// GTFS Transit Feed extraction and analysis
//
// Parses GTFS static feeds (ZIP/CSV) to extract:
// - Stop locations and metadata
// - Route geometries (from shapes.txt or stop sequences)
// - Service frequency per stop
// - Transit coverage and accessibility metrics
//
// Integrates with OSM data for multimodal analysis:
// - Nearest-stop lookups against OSM features
// - Walk-distance accessibility bands
// - Coverage gap detection (OSM features without nearby transit)
// - Route density heatmaps

/** GTFS transit feed extraction, OSM integration, and coverage analysis. */
namespace osm.Transit.GTFS {
    use osm.types

    /** Extracted transit stop locations with bounding box. */
    schema StopResult {
        output_path: String,
        stop_count: Long,
        bbox_min_lat: Double,
        bbox_min_lon: Double,
        bbox_max_lat: Double,
        bbox_max_lon: Double,
        format: String,
        extraction_date: String
    }

    /** Extracted transit route geometries. */
    schema GTFSRouteFeatures {
        output_path: String,
        route_count: Long,
        has_shapes: Boolean,
        route_types: String,
        format: String,
        extraction_date: String
    }

    /** Per-stop service frequency data. */
    schema FrequencyResult {
        output_path: String,
        stop_count: Long,
        avg_trips_per_day: Double,
        max_trips_per_day: Long,
        service_date: String,
        format: String,
        extraction_date: String
    }

    /** Aggregate transit statistics by route type. */
    schema TransitStats {
        agency_name: String,
        stop_count: Long,
        route_count: Long,
        trip_count: Long,
        has_shapes: Boolean,
        route_type_counts: String,
        extraction_date: String
    }

    /** Result of matching OSM features to their nearest transit stops. */
    schema NearestStopResult {
        output_path: String,
        feature_count: Long,
        matched_count: Long,
        avg_distance_m: Double,
        max_distance_m: Double,
        format: String,
        extraction_date: String
    }

    /** Walk-distance accessibility bands around transit stops. */
    schema AccessibilityResult {
        output_path: String,
        total_features: Long,
        within_400m: Long,
        within_800m: Long,
        beyond_800m: Long,
        pct_within_400m: Double,
        pct_within_800m: Double,
        format: String,
        extraction_date: String
    }

    /** Grid-based transit coverage gap analysis. */
    schema CoverageResult {
        output_path: String,
        total_cells: Long,
        covered_cells: Long,
        gap_cells: Long,
        coverage_pct: Double,
        format: String,
        extraction_date: String
    }

    /** Route density heatmap per grid cell. */
    schema DensityResult {
        output_path: String,
        total_cells: Long,
        max_routes_per_cell: Long,
        avg_routes_per_cell: Double,
        format: String,
        extraction_date: String
    }

    /** Consolidated transit analysis report with all output paths. */
    schema TransitReport {
        feed_agency: String,
        stop_count: Long,
        route_count: Long,
        trip_count: Long,
        has_shapes: Boolean,
        stops_path: String,
        routes_path: String,
        frequency_path: String,
        osm_integration: Boolean,
        nearest_stops_path: String,
        accessibility_path: String,
        coverage_path: String,
        density_path: String,
        extraction_date: String
    }

    /** Downloads and extracts a GTFS static feed from a URL. */
    event facet DownloadFeed(url: String) => (feed: GTFSFeed)

    /** Extracts stop locations to GeoJSON points. */
    event facet ExtractStops(feed: GTFSFeed) => (result: StopResult)

    /** Extracts route geometries to GeoJSON linestrings. */
    event facet ExtractRoutes(feed: GTFSFeed) => (result: GTFSRouteFeatures)

    /** Computes trips-per-stop-per-day from stop_times and calendar. */
    event facet ServiceFrequency(feed: GTFSFeed) => (result: FrequencyResult)

    /** Computes aggregate transit statistics by route type. */
    event facet TransitStatistics(feed: GTFSFeed) => (stats: TransitStats)

    /** Finds the nearest transit stop for each OSM feature. */
    event facet NearestStops(osm_geojson_path: String,
        stops_geojson_path: String,
        max_distance_m: Long = 2000) => (result: NearestStopResult)

    /** Classifies OSM features into walk-distance bands around transit stops. */
    event facet StopAccessibility(osm_geojson_path: String,
        stops_geojson_path: String,
        walk_threshold_m: Long = 400) => (result: AccessibilityResult)

    /** Detects grid-based transit coverage gaps. */
    event facet CoverageGaps(stops_geojson_path: String,
        osm_geojson_path: String,
        cell_size_m: Long = 500) => (result: CoverageResult)

    /** Computes route density per grid cell. */
    event facet RouteDensity(routes_geojson_path: String,
        cell_size_m: Long = 500) => (result: DensityResult)

    /** Runs all analyses and produces a consolidated transit report. */
    event facet GenerateReport(feed: GTFSFeed,
        osm_geojson_path: String = "") => (report: TransitReport)
}


// OSM route extraction for various transport modes
//
// Extracts routes and related infrastructure from OSM data for:
// - bicycle: Cycle routes, cycleways, bike infrastructure
// - hiking: Hiking/walking trails, footpaths
// - train: Railway lines, stations
// - bus: Bus routes, stops

/** Route extraction for bicycle, hiking, train, and bus transport modes. */
namespace osm.Routes {
    use osm.types

    /** Extracted route data with type, network level, and infrastructure flags. */
    schema RouteFeatures {
        output_path: String,
        feature_count: Long,
        route_type: String,
        network_level: String,
        include_infrastructure: Boolean,
        format: String,
        extraction_date: String
    }

    /** Aggregate statistics for extracted routes including total length. */
    schema RouteStats {
        route_count: Long,
        total_length_km: Double,
        infrastructure_count: Long,
        route_type: String
    }

    /** Extracts routes by transport type with optional network and infrastructure filtering. */
    event facet ExtractRoutes(cache: OSMCache, route_type: String,
        network: String = "*", include_infrastructure: Boolean = true) => (result: RouteFeatures)

    /** Filters pre-extracted GeoJSON routes by transport type and network. */
    event facet FilterRoutesByType(input_path: String, route_type: String,
        network: String = "*") => (result: RouteFeatures)

    /** Computes aggregate statistics for extracted routes. */
    event facet RouteStatistics(input_path: String) => (stats: RouteStats)

    /** Extracts bicycle routes and cycling infrastructure. */
    event facet BicycleRoutes(cache: OSMCache, network: String = "*",
        include_infrastructure: Boolean = true) => (result: RouteFeatures)

    /** Extracts hiking and walking trails. */
    event facet HikingTrails(cache: OSMCache, network: String = "*",
        include_infrastructure: Boolean = true) => (result: RouteFeatures)

    /** Extracts railway lines and stations. */
    event facet TrainRoutes(cache: OSMCache,
        include_infrastructure: Boolean = true) => (result: RouteFeatures)

    /** Extracts bus routes and stops. */
    event facet BusRoutes(cache: OSMCache,
        include_infrastructure: Boolean = true) => (result: RouteFeatures)

    /** Extracts all public transport routes across modes. */
    event facet PublicTransport(cache: OSMCache) => (result: RouteFeatures)
}


// Routing Adapter: Public API (OSRM demo / OpenRouteService)
//
// Zero-import routing via public HTTP APIs. No local graph build needed.
// Uses OSRM demo server by default; set AFL_ORS_API_KEY for OpenRouteService.

/** API routing adapter — routes via public HTTP APIs (OSRM demo or OpenRouteService). */
namespace osm.Routing.API {
    use osm.Routing.Types

    /** Compute a point-to-point route between two waypoints via API. */
    event facet Route(
        from_lat: Double,
        from_lon: Double,
        from_name: String = "",
        to_lat: Double,
        to_lon: Double,
        to_name: String = "",
        profile: String = "car"
    ) => (result: PointToPointResult)

    /** Compute a multi-stop route through an ordered list of waypoints via API. */
    event facet MultiStopRoute(
        waypoints: String,
        profile: String = "car"
    ) => (result: MultiStopResult)

    /** Compute an isochrone (reachability polygon) from a center point via API. */
    event facet Isochrone(
        center_lat: Double,
        center_lon: Double,
        center_name: String = "",
        time_minutes: Long = 15,
        profile: String = "car"
    ) => (result: IsochroneResult)
}


// Routing Adapter: Local OSRM server
//
// Routes via a locally running OSRM instance. Requires OSRM to be set up
// with a pre-processed PBF for the target region.
//
// Set AFL_OSRM_URL (default: http://localhost:5000) to point to your instance.

/** OSRM local routing adapter — routes via a self-hosted OSRM server. */
namespace osm.Routing.OSRM {
    use osm.Routing.Types

    /** Compute a point-to-point route between two waypoints via local OSRM. */
    event facet Route(
        from_lat: Double,
        from_lon: Double,
        from_name: String = "",
        to_lat: Double,
        to_lon: Double,
        to_name: String = "",
        profile: String = "car"
    ) => (result: PointToPointResult)

    /** Compute a multi-stop route through an ordered list of waypoints via local OSRM. */
    event facet MultiStopRoute(
        waypoints: String,
        profile: String = "car"
    ) => (result: MultiStopResult)

    /** Compute an isochrone (reachability polygon) from a center point via local OSRM. */
    event facet Isochrone(
        center_lat: Double,
        center_lon: Double,
        center_name: String = "",
        time_minutes: Long = 15,
        profile: String = "car"
    ) => (result: IsochroneResult)
}


// Routing adapter types — shared across all routing backends
//
// Defines common schemas for point-to-point and multi-stop routing
// results so that downstream workflows work identically regardless
// of whether the route came from an API, OSRM, or GraphHopper.

/** Shared routing types for the source adapter pattern. */
namespace osm.Routing.Types {

    /** A geographic coordinate for routing waypoints. */
    schema Waypoint {
        lon: Double,
        lat: Double,
        name: String
    }

    /** A single computed route between two points. */
    schema RouteResult {
        from_name: String,
        to_name: String,
        distance_km: Double,
        duration_min: Double,
        output_path: String,
        profile: String,
        backend: String,
        format: String
    }

    /** Result of routing between two waypoints. */
    schema PointToPointResult {
        route: RouteResult,
        waypoint_count: Long
    }

    /** Result of a multi-stop route through an ordered list of waypoints. */
    schema MultiStopResult {
        output_path: String,
        leg_count: Long,
        total_distance_km: Double,
        total_duration_min: Double,
        profile: String,
        backend: String,
        format: String
    }

    /** Result of an isochrone (reachability area) computation. */
    schema IsochroneResult {
        output_path: String,
        center_name: String,
        time_minutes: Long,
        profile: String,
        backend: String,
        format: String
    }
}


// Composed routing workflows — same pipeline, different backends
//
// Demonstrates the routing source adapter pattern:
// - RouteViaAPI: uses public API (no setup)
// - RouteViaOSRM: uses local OSRM server (fast, offline)
//
// All produce identical output schemas so downstream steps
// (rendering, analysis) work regardless of routing backend.

/** Composed routing workflows using different backends. */
namespace osm.Routing.Workflows {
    use osm.Routing.Types
    use osm.Routing.API
    use osm.Routing.OSRM
    use osm.viz

    /** Route between two points via public API and render the result. */
    workflow RouteViaAPI(
        from_lat: Double,
        from_lon: Double,
        from_name: String,
        to_lat: Double,
        to_lon: Double,
        to_name: String,
        profile: String = "car",
        color: String = "#2980b9"
    ) => (
        distance_km: Double,
        duration_min: Double,
        map_path: String
    ) andThen {
        route = osm.Routing.API.Route(
            from_lat = $.from_lat, from_lon = $.from_lon, from_name = $.from_name,
            to_lat = $.to_lat, to_lon = $.to_lon, to_name = $.to_name,
            profile = $.profile
        )
        map = RenderMap(
            geojson_path = route.result.route.output_path,
            title = $.from_name ++ " to " ++ $.to_name,
            color = $.color
        )
        yield RouteViaAPI(
            distance_km = route.result.route.distance_km,
            duration_min = route.result.route.duration_min,
            map_path = map.result.output_path
        )
    }

    /** Route between two points via local OSRM and render the result. */
    workflow RouteViaOSRM(
        from_lat: Double,
        from_lon: Double,
        from_name: String,
        to_lat: Double,
        to_lon: Double,
        to_name: String,
        profile: String = "car",
        color: String = "#e74c3c"
    ) => (
        distance_km: Double,
        duration_min: Double,
        map_path: String
    ) andThen {
        route = osm.Routing.OSRM.Route(
            from_lat = $.from_lat, from_lon = $.from_lon, from_name = $.from_name,
            to_lat = $.to_lat, to_lon = $.to_lon, to_name = $.to_name,
            profile = $.profile
        )
        map = RenderMap(
            geojson_path = route.result.route.output_path,
            title = $.from_name ++ " to " ++ $.to_name,
            color = $.color
        )
        yield RouteViaOSRM(
            distance_km = route.result.route.distance_km,
            duration_min = route.result.route.duration_min,
            map_path = map.result.output_path
        )
    }

    /** Multi-stop route via API with map rendering. */
    workflow MultiStopViaAPI(
        waypoints: String,
        profile: String = "car",
        title: String = "Multi-Stop Route",
        color: String = "#27ae60"
    ) => (
        leg_count: Long,
        total_distance_km: Double,
        total_duration_min: Double,
        map_path: String
    ) andThen {
        route = osm.Routing.API.MultiStopRoute(
            waypoints = $.waypoints,
            profile = $.profile
        )
        map = RenderMap(
            geojson_path = route.result.output_path,
            title = $.title,
            color = $.color
        )
        yield MultiStopViaAPI(
            leg_count = route.result.leg_count,
            total_distance_km = route.result.total_distance_km,
            total_duration_min = route.result.total_duration_min,
            map_path = map.result.output_path
        )
    }

    /** Isochrone (reachability area) via API with map rendering. */
    workflow IsochroneViaAPI(
        center_lat: Double,
        center_lon: Double,
        center_name: String = "",
        time_minutes: Long = 15,
        profile: String = "car",
        color: String = "#8e44ad"
    ) => (
        map_path: String,
        time_minutes: Long
    ) andThen {
        iso = osm.Routing.API.Isochrone(
            center_lat = $.center_lat,
            center_lon = $.center_lon,
            center_name = $.center_name,
            time_minutes = $.time_minutes,
            profile = $.profile
        )
        map = RenderMap(
            geojson_path = iso.result.output_path,
            title = $.center_name ++ " " ++ $.time_minutes ++ "min reachability",
            color = $.color
        )
        yield IsochroneViaAPI(
            map_path = map.result.output_path,
            time_minutes = $.time_minutes
        )
    }
}


