    event facet ExtractParks(source: PostGISSource, park_type: String = "all", protect_classes: String = "*") => (result: osm.Parks.ParkFeatures)

    /** Extracts building footprints from PostGIS. */
    event facet ExtractBuildings(source: PostGISSource, building_type: String = "all") => (result: osm.Buildings.BuildingFeatures)

    /** Extracts administrative and natural boundaries from PostGIS. */
    event facet ExtractBoundaries(source: PostGISSource, boundary_type: String = "admin", admin_level: Long = 2) => (result: osm.Boundaries.BoundaryFeatures)

