}


// Source-Agnostic Composed Workflows
//
// These workflows demonstrate how the same analysis pipelines work
// with different data sources (PBF, PostGIS, GeoJSON). The analysis
// facets (statistics, filtering, visualization) are reused across
// all source types — only the extraction layer changes.

/** Source-agnostic workflows: same analysis pipelines across PBF, PostGIS, and GeoJSON sources. */
namespace osm.workflows.sourced {
    use osm.types

    // ==========================================================================
    // ROUTES: Three sources → same analysis pipeline
    // ==========================================================================

    /** Extracts bicycle routes from PBF, computes statistics, and renders a map. */
    workflow BicycleRoutesPBF(region: String = "Liechtenstein") => (map_path: String, route_count: Long, total_km: Double) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        routes = osm.Source.PBF.ExtractRoutes(cache = cache.cache, route_type = "bicycle")
        stats = osm.Routes.RouteStatistics(input_path = routes.result.output_path)
        map = osm.viz.RenderMap(geojson_path = routes.result.output_path, title = "Bicycle Routes (PBF)", color = "#27ae60")
        yield BicycleRoutesPBF(map_path = map.result.output_path, route_count = routes.result.feature_count, total_km = stats.stats.total_length_km)
    }

    /** Extracts bicycle routes from PostGIS, computes statistics, and renders a map. */
    workflow BicycleRoutesPostGIS(postgis_url: String = "postgresql://afl_osm:afl_osm_2024@afl-postgres:5432/osm", region: String = "Liechtenstein") => (map_path: String, route_count: Long, total_km: Double) andThen {
        routes = osm.Source.PostGIS.ExtractRoutes(source = #{"postgis_url": $.postgis_url, "region": $.region}, route_type = "bicycle")
        stats = osm.Routes.RouteStatistics(input_path = routes.result.output_path)
        map = osm.viz.RenderMap(geojson_path = routes.result.output_path, title = "Bicycle Routes (PostGIS)", color = "#27ae60")
        yield BicycleRoutesPostGIS(map_path = map.result.output_path, route_count = routes.result.feature_count, total_km = stats.stats.total_length_km)
    }

    /** Loads bicycle routes from existing GeoJSON, computes statistics, and renders a map. */
    workflow BicycleRoutesGeoJSON(input_path: String) => (map_path: String, route_count: Long, total_km: Double) andThen {
        routes = osm.Source.GeoJSON.LoadRoutes(input_path = $.input_path, route_type = "bicycle")
        stats = osm.Routes.RouteStatistics(input_path = routes.result.output_path)
        map = osm.viz.RenderMap(geojson_path = routes.result.output_path, title = "Bicycle Routes (GeoJSON)", color = "#27ae60")
        yield BicycleRoutesGeoJSON(map_path = map.result.output_path, route_count = routes.result.feature_count, total_km = stats.stats.total_length_km)
    }

    /** Extracts hiking trails from PostGIS with elevation enrichment. */
    workflow HikingTrailsPostGIS(postgis_url: String = "postgresql://afl_osm:afl_osm_2024@afl-postgres:5432/osm", region: String = "Liechtenstein") => (map_path: String, trail_count: Long, total_km: Double) andThen {
        routes = osm.Source.PostGIS.ExtractRoutes(source = #{"postgis_url": $.postgis_url, "region": $.region}, route_type = "hiking")
        stats = osm.Routes.RouteStatistics(input_path = routes.result.output_path)
        map = osm.viz.RenderMap(geojson_path = routes.result.output_path, title = "Hiking Trails (PostGIS)", color = "#8e44ad")
        yield HikingTrailsPostGIS(map_path = map.result.output_path, trail_count = routes.result.feature_count, total_km = stats.stats.total_length_km)
    }

    // ==========================================================================
    // AMENITIES: PostGIS-backed analysis
    // ==========================================================================

    /** Extracts amenities from PostGIS and computes statistics. */
    workflow AnalyzeAmenitiesPostGIS(postgis_url: String = "postgresql://afl_osm:afl_osm_2024@afl-postgres:5432/osm", region: String = "Liechtenstein", category: String = "all") => (amenity_count: Long, map_path: String) andThen {
        amenities = osm.Source.PostGIS.ExtractAmenities(source = #{"postgis_url": $.postgis_url, "region": $.region}, category = $.category)
        map = osm.viz.RenderMap(geojson_path = amenities.result.output_path, title = "Amenities (PostGIS)", color = "#e74c3c")
        yield AnalyzeAmenitiesPostGIS(amenity_count = amenities.result.feature_count, map_path = map.result.output_path)
    }

    /** Extracts healthcare amenities from PostGIS and renders a map. */
    workflow HealthcareMapPostGIS(postgis_url: String = "postgresql://afl_osm:afl_osm_2024@afl-postgres:5432/osm", region: String = "Liechtenstein") => (hospital_count: Long, map_path: String) andThen {
        hospitals = osm.Source.PostGIS.ExtractAmenities(source = #{"postgis_url": $.postgis_url, "region": $.region}, category = "healthcare")
        map = osm.viz.RenderMap(geojson_path = hospitals.result.output_path, title = "Healthcare Facilities (PostGIS)", color = "#e74c3c")
        yield HealthcareMapPostGIS(hospital_count = hospitals.result.feature_count, map_path = map.result.output_path)
    }

    // ==========================================================================
    // ROADS: Compare PBF vs PostGIS extraction
    // ==========================================================================

    /** Extracts major roads from PBF and renders a map. */
    workflow MajorRoadsPBF(region: String = "Liechtenstein") => (road_count: Long, map_path: String) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        roads = osm.Source.PBF.ExtractRoads(cache = cache.cache, road_class = "major")
        stats = osm.Roads.RoadStatistics(input_path = roads.result.output_path)
        map = osm.viz.RenderMap(geojson_path = roads.result.output_path, title = "Major Roads (PBF)", color = "#2980b9")
        yield MajorRoadsPBF(road_count = roads.result.feature_count, map_path = map.result.output_path)
    }

    /** Extracts major roads from PostGIS and renders a map. */
    workflow MajorRoadsPostGIS(postgis_url: String = "postgresql://afl_osm:afl_osm_2024@afl-postgres:5432/osm", region: String = "Liechtenstein") => (road_count: Long, map_path: String) andThen {
        roads = osm.Source.PostGIS.ExtractRoads(source = #{"postgis_url": $.postgis_url, "region": $.region}, road_class = "major")
        stats = osm.Roads.RoadStatistics(input_path = roads.result.output_path)
        map = osm.viz.RenderMap(geojson_path = roads.result.output_path, title = "Major Roads (PostGIS)", color = "#2980b9")
        yield MajorRoadsPostGIS(road_count = roads.result.feature_count, map_path = map.result.output_path)
    }

    // ==========================================================================
    // PARKS: All three sources
    // ==========================================================================

    /** Extracts parks from PBF and computes statistics. */
    workflow AnalyzeParksPBF(region: String = "Liechtenstein") => (total_parks: Long, total_area: Double) andThen {
        cache = osm.ops.CacheRegion(region = $.region)
        parks = osm.Source.PBF.ExtractParks(cache = cache.cache, park_type = "all")
        stats = osm.Parks.ParkStatistics(input_path = parks.result.output_path)
        yield AnalyzeParksPBF(total_parks = stats.stats.total_parks, total_area = stats.stats.total_area_km2)
    }

    /** Extracts parks from PostGIS and computes statistics. */
    workflow AnalyzeParksPostGIS(postgis_url: String = "postgresql://afl_osm:afl_osm_2024@afl-postgres:5432/osm", region: String = "Liechtenstein") => (total_parks: Long, total_area: Double) andThen {
        parks = osm.Source.PostGIS.ExtractParks(source = #{"postgis_url": $.postgis_url, "region": $.region}, park_type = "all")
        stats = osm.Parks.ParkStatistics(input_path = parks.result.output_path)
        yield AnalyzeParksPostGIS(total_parks = stats.stats.total_parks, total_area = stats.stats.total_area_km2)
    }

    /** Loads parks from GeoJSON and computes statistics. */
    workflow AnalyzeParksGeoJSON(input_path: String) => (total_parks: Long, total_area: Double) andThen {
        parks = osm.Source.GeoJSON.LoadParks(input_path = $.input_path, park_type = "all")
        stats = osm.Parks.ParkStatistics(input_path = parks.result.output_path)
        yield AnalyzeParksGeoJSON(total_parks = stats.stats.total_parks, total_area = stats.stats.total_area_km2)
    }

    // ==========================================================================
    // POPULATION: PostGIS-backed city analysis
    // ==========================================================================

    /** Extracts populated cities from PostGIS, filters by minimum population, and renders a map. */
    workflow LargeCitiesPostGIS(postgis_url: String = "postgresql://afl_osm:afl_osm_2024@afl-postgres:5432/osm", region: String = "Liechtenstein", min_pop: Long = 10000) => (city_count: Long, map_path: String) andThen {
        cities = osm.Source.PostGIS.ExtractPopulation(source = #{"postgis_url": $.postgis_url, "region": $.region}, place_type = "city", min_population = $.min_pop)
        map = osm.viz.RenderMap(geojson_path = cities.result.output_path, title = "Large Cities (PostGIS)", color = "#f39c12")
        yield LargeCitiesPostGIS(city_count = cities.result.feature_count, map_path = map.result.output_path)
    }

    // ==========================================================================
    // BUILDINGS: PostGIS-backed building analysis
    // ==========================================================================

    /** Extracts buildings from PostGIS and renders a map. */
    workflow BuildingMapPostGIS(postgis_url: String = "postgresql://afl_osm:afl_osm_2024@afl-postgres:5432/osm", region: String = "Liechtenstein", building_type: String = "all") => (building_count: Long, map_path: String) andThen {
        buildings = osm.Source.PostGIS.ExtractBuildings(source = #{"postgis_url": $.postgis_url, "region": $.region}, building_type = $.building_type)
        stats = osm.Buildings.BuildingStatistics(input_path = buildings.result.output_path)
        map = osm.viz.RenderMap(geojson_path = buildings.result.output_path, title = "Buildings (PostGIS)", color = "#95a5a6")
        yield BuildingMapPostGIS(building_count = buildings.result.feature_count, map_path = map.result.output_path)
    }

    // ==========================================================================
    // BOUNDARIES: PostGIS-backed boundary extraction
    // ==========================================================================

    /** Extracts state boundaries from PostGIS and renders a map. */
    workflow StateBoundariesPostGIS(postgis_url: String = "postgresql://afl_osm:afl_osm_2024@afl-postgres:5432/osm", region: String = "Liechtenstein") => (boundary_count: Long, map_path: String) andThen {
        boundaries = osm.Source.PostGIS.ExtractBoundaries(source = #{"postgis_url": $.postgis_url, "region": $.region}, boundary_type = "state", admin_level = 4)
        map = osm.viz.RenderMap(geojson_path = boundaries.result.output_path, title = "State Boundaries (PostGIS)", color = "#1abc9c")
        yield StateBoundariesPostGIS(boundary_count = boundaries.result.feature_count, map_path = map.result.output_path)
    }

    // ==========================================================================
    // MULTI-SOURCE: Combined analysis from multiple sources
    // ==========================================================================

    /** Extracts roads from PostGIS and parks from PostGIS concurrently, renders both as layers. */
    workflow RoadsAndParksPostGIS(postgis_url: String = "postgresql://afl_osm:afl_osm_2024@afl-postgres:5432/osm", region: String = "Liechtenstein") => (road_count: Long, park_count: Long, map_path: String) andThen {
        roads = osm.Source.PostGIS.ExtractRoads(source = #{"postgis_url": $.postgis_url, "region": $.region}, road_class = "major")
        parks = osm.Source.PostGIS.ExtractParks(source = #{"postgis_url": $.postgis_url, "region": $.region}, park_type = "all")
        map = osm.viz.RenderLayers(layers = [roads.result.output_path, parks.result.output_path], colors = ["#2980b9", "#27ae60"], title = "Roads & Parks (PostGIS)")
        yield RoadsAndParksPostGIS(road_count = roads.result.feature_count, park_count = parks.result.feature_count, map_path = map.result.output_path)
    }
}


// Valhalla routing tileset operations.
// Takes an OSM cache as input, builds tile pyramids.

/** Valhalla routing tileset construction and management. */
namespace osm.ops.Valhalla {
    use osm.types

    /** Builds (or returns cached) Valhalla tileset for a region. Valhalla tiles are profile-agnostic — one build serves auto/bicycle/pedestrian/truck/etc. at query time. */
    event facet BuildTiles(cache: OSMCache, recreate: Boolean = false) => (tiles: ValhallaCache)

    /** Bulk-mode equivalent of BuildTiles for FFL batch loops. */
    event facet BuildTilesBatch(cache: OSMCache, recreate: Boolean = false) => (tiles: ValhallaCache)

    /** Validates an existing tileset: confirms it exists and returns tile count. */
    event facet ValidateTiles(tiles: ValhallaCache) => (valid: Boolean, tileCount: Long)

    /** Deletes a built tileset directory. */
    event facet CleanTiles(tiles: ValhallaCache) => (deleted: Boolean)
}


// GeoJSON visualization with OSM map backgrounds
//
// Generates interactive HTML maps using Leaflet.js with OpenStreetMap tiles,
// or static PNG images for embedding in documents.

/** Map rendering and GeoJSON formatting using Leaflet.js with OSM tiles. */
namespace osm.viz {
    /** Rendered map output with bounds, format, and feature count. */
    schema MapResult {
        output_path: String,
        format: String,
        feature_count: Long,
        bounds: String,
        title: String,
        extraction_date: String
    }

    /** Custom style parameters for map layer rendering. */
    schema LayerStyle {
        color: String,
        fill_color: String,
        weight: Long,
        opacity: Double,
        fill_opacity: Double
    }
    /** Generates an interactive HTML or static PNG map from GeoJSON. */
    event facet RenderMap(geojson_path: String, title: String = "Map",
        format: String = "html", width: Long = 800, height: Long = 600,
        color: String = "#3388ff") => (result: MapResult)

    /** Renders a map centered on specific coordinates with a zoom level. */
    event facet RenderMapAt(geojson_path: String, lat: Double, lon: Double,
        zoom: Long = 10, title: String = "Map") => (result: MapResult)

    /** Renders multiple GeoJSON files as color-coded layers. */
    event facet RenderLayers(layers: [String], colors: [String],
        title: String = "Map", format: String = "html") => (result: MapResult)

    /** Renders a map with custom layer styling. */
    event facet RenderStyledMap(geojson_path: String, style: LayerStyle,
        title: String = "Map") => (result: MapResult)

    /** Opens a quick browser preview of GeoJSON data. */
    event facet PreviewMap(geojson_path: String) => (result: MapResult)

    /** Formatted text output from GeoJSON features. */
    schema FormatResult {
        output_path: String,
        text: String,
        feature_count: Long,
        format: String,
        title: String
    }

    /** Formats GeoJSON features as text or other output formats. */
    event facet FormatGeoJSON(input_path: String, title: String = "Features",
        format: String = "text") => (result: FormatResult)
}


// US Census TIGER/Line voting district data
//
// Downloads and processes electoral boundary data from the US Census Bureau.
// Supports Congressional Districts, State Legislative Districts, and Voting Precincts.
//
// Parameter guide:
//   state   — US state name ("California"), abbreviation ("CA"), or FIPS code ("06").
//             Required for all district types.
//   year    — TIGER/Line data year.  Available: 2020, 2021, 2022, 2023, 2024.
//             Not all district types exist for all years.
//             Congressional Districts: 2020-2024 (per-state files starting 2023).
//             State Legislative Districts: 2020-2024.
//             Voting Precincts: 2020 only (decennial census).
//   congress_number — Congress number for CD boundaries.  Auto-derived from year
//             if omitted.  Known mappings: 2020-2022→116, 2023→118, 2024→119.
//
// Examples:
//   CongressionalDistricts(state = "California", year = 2024)
//   CongressionalDistricts(state = "NY", year = 2024, congress_number = 119)
//   StateSenateDistricts(state = "Texas", year = 2024)
//   GetCongressionalDistricts(state = "CA")
//   GetStateVotingBoundaries(state = "Florida", year = 2024)

/** Shared type definitions for US Census TIGER/Line electoral boundary data. */
namespace census.types {
    /** Cached TIGER/Line shapefile download metadata. */
    schema TIGERCache {
        url: String,
        path: String,
        date: String,
        size: Long,
        wasInCache: Boolean,
        year: Long,
        district_type: String,
        state: String
    }

    /** Result of a voting-district extraction or conversion operation. */
    schema VotingDistrictResult {
        output_path: String,
        feature_count: Long,
        district_type: String,
        state: String,
        year: Long,
        format: String,
        extraction_date: String
    }
}

/** Event facets for downloading TIGER/Line electoral boundary shapefiles from the US Census Bureau. */
namespace census.tiger.Districts {
    use census.types

    /** Downloads Congressional District boundaries for a state.
        Congress number is auto-derived from year if not specified.
        For year >= 2023, files are per-state from Census.gov.
        @param state  State name, abbreviation, or FIPS code (e.g. "California", "CA", "06")
        @param year   TIGER data year: 2020-2024 (default 2024)
        @param congress_number  Congress number; auto-derived if omitted (2024→119)
        @returns cache  Download metadata including local path to ZIP file */
    event facet CongressionalDistricts(state: String,
        year: Long = 2024,
        congress_number: Long = 119) => (cache: TIGERCache)

    /** Downloads state senate (upper chamber) district boundaries.
        @param state  State name, abbreviation, or FIPS code
        @param year   TIGER data year: 2020-2024 (default 2024) */
    event facet StateSenateDistricts(state: String,
        year: Long = 2024) => (cache: TIGERCache)

    /** Downloads state house/assembly (lower chamber) district boundaries.
        @param state  State name, abbreviation, or FIPS code
        @param year   TIGER data year: 2020-2024 (default 2024) */
    event facet StateHouseDistricts(state: String,
        year: Long = 2024) => (cache: TIGERCache)

    /** Downloads voting precinct boundaries (decennial census only).
        @param state  State name, abbreviation, or FIPS code
        @param year   Decennial census year: 2020 (default), 2010 */
    event facet VotingPrecincts(state: String,
        year: Long = 2020) => (cache: TIGERCache)

    /** Downloads senate, house, and precinct boundaries for a state in one call.
        @param state  State name, abbreviation, or FIPS code
        @param year   TIGER data year: 2020-2024 (default 2024) */
    event facet AllStateDistricts(state: String,
        year: Long = 2024) => (senate: TIGERCache, house: TIGERCache, precincts: TIGERCache)
}

/** Processing facets for converting and filtering TIGER/Line shapefiles. */
namespace census.tiger.Processing {
    use census.types

    /** Converts a downloaded TIGER shapefile to GeoJSON format.
        Requires ogr2ogr (GDAL) or geopandas. */
    event facet ShapefileToGeoJSON(cache: TIGERCache) => (result: VotingDistrictResult)

    /** Spatially joins voting districts with OSM administrative boundaries. */
    event facet JoinWithOSMBoundaries(districts: VotingDistrictResult,
        osm_boundaries_path: String) => (result: VotingDistrictResult)

    /** Filters districts by a named attribute (e.g., district number or name). */
    event facet FilterDistricts(input_path: String,
        attribute: String, value: String) => (result: VotingDistrictResult)
}

// Convenience workflows for common use cases

/** Convenience workflows for common electoral boundary retrieval tasks. */
namespace census.tiger.Workflows {
    use census.types

    /** Looks up the 2-digit FIPS code for a state name or abbreviation. */
    facet StateFIPS(state: String) => (fips: String)

    /** Downloads Congressional District boundaries for a state and converts them to GeoJSON.
        @param state  State name, abbreviation, or FIPS code (e.g. "California", "CA", "06")
        @param year   TIGER data year: 2020-2024 (default 2024)
        @param congress_number  Congress number; auto-derived if omitted */
    workflow GetCongressionalDistricts(state: String, year: Long = 2024, congress_number: Long = 119) => (result: VotingDistrictResult) andThen {
        download = census.tiger.Districts.CongressionalDistricts(state = $.state, year = $.year, congress_number = $.congress_number)
        convert = census.tiger.Processing.ShapefileToGeoJSON(cache = download.cache)
        yield GetCongressionalDistricts(result = convert.result)
    }

    /** Downloads and converts senate, house, and precinct boundaries for a state to GeoJSON.
        @param state  State name, abbreviation, or FIPS code
        @param year   TIGER data year: 2020-2024 (default 2024); precincts always use 2020 */
    workflow GetStateVotingBoundaries(state: String, year: Long = 2024) => (senate: VotingDistrictResult, house: VotingDistrictResult, precincts: VotingDistrictResult) andThen {
        senate_dl = census.tiger.Districts.StateSenateDistricts(state = $.state, year = $.year)
        house_dl = census.tiger.Districts.StateHouseDistricts(state = $.state, year = $.year)
        precincts_dl = census.tiger.Districts.VotingPrecincts(state = $.state, year = 2020)

        senate_json = census.tiger.Processing.ShapefileToGeoJSON(cache = senate_dl.cache)
        house_json = census.tiger.Processing.ShapefileToGeoJSON(cache = house_dl.cache)
        precincts_json = census.tiger.Processing.ShapefileToGeoJSON(cache = precincts_dl.cache)

        yield GetStateVotingBoundaries(senate = senate_json.result, house = house_json.result, precincts = precincts_json.result)
    }
}


// Simplest integration test workflow: AddOne
//
// Demonstrates the full pipeline: AFL source -> compile -> MongoStore ->
// Evaluator -> AgentPoller -> handler -> completion.

/** Provides a minimal event facet that increments an integer by one. */
namespace handlers {
    /** Accepts an integer and returns it incremented by one. */
    event facet AddOne(input: Long) => (output: Long)
}

/** Integration test verifying the complete AFL compile-to-execution pipeline. */
namespace test {
    use handlers

    /** Invokes AddOne and returns the incremented result. */
    workflow TestAddOne(x: Long) => (result: Long) andThen {
        step = AddOne(input = $.x)
        yield TestAddOne(result = step.output)
    }
}


/** Runs all composed analysis workflows for US states. */
namespace osm.UnitedStates.analysis {
  use osm.types

  /** Runs comprehensive analysis for a single region using one CombinedScan pass. */
  workflow AnalyzeRegion(region: String = "Liechtenstein") => (completed_region: String) andThen {
    // Stage 1: Cache the PBF file
    cache = osm.ops.CacheRegion(region = $.region)

    // Stage 2: Single-pass extraction for all needed categories
    scan = osm.Combined.CombinedScan(cache = cache.cache, categories = ["routes", "parks", "population", "boundaries"])

    // Stage 3: Extract per-category output paths from the scan results
    routesData = osm.Combined.ExtractCategoryResult(results = scan.results, category = "routes")
    parksData = osm.Combined.ExtractCategoryResult(results = scan.results, category = "parks")
    populationData = osm.Combined.ExtractCategoryResult(results = scan.results, category = "population")
    boundariesData = osm.Combined.ExtractCategoryResult(results = scan.results, category = "boundaries")

    // Stage 4: Post-processing — all steps below run in parallel where dependencies allow

    // -- Bicycle routes visualization (was VisualizeBicycleRoutesFromCache)
    bicycleRoutes = osm.Routes.FilterRoutesByType(input_path = routesData.output_path, route_type = "bicycle")
    bicycleMap = osm.viz.RenderMap(geojson_path = bicycleRoutes.result.output_path, title = "Bicycle Routes", color = "#27ae60")

    // -- Transport overview: 4 route types with stats (was TransportOverviewFromCache)
    hikingRoutes = osm.Routes.FilterRoutesByType(input_path = routesData.output_path, route_type = "hiking")
    trainRoutes = osm.Routes.FilterRoutesByType(input_path = routesData.output_path, route_type = "train")
    busRoutes = osm.Routes.FilterRoutesByType(input_path = routesData.output_path, route_type = "bus")
    bicycleStats = osm.Routes.RouteStatistics(input_path = bicycleRoutes.result.output_path)
    hikingStats = osm.Routes.RouteStatistics(input_path = hikingRoutes.result.output_path)
    trainStats = osm.Routes.RouteStatistics(input_path = trainRoutes.result.output_path)
    busStats = osm.Routes.RouteStatistics(input_path = busRoutes.result.output_path)

    // -- Park analysis with stats (was AnalyzeParksFromCache)
    parkStats = osm.Parks.ParkStatistics(input_path = parksData.output_path)

    // -- National parks: filter + stats + map (was NationalParksAnalysisFromCache)
    nationalParks = osm.Parks.FilterParksByType(input_path = parksData.output_path, park_type = "national")
    nationalParkStats = osm.Parks.ParkStatistics(input_path = nationalParks.result.output_path)
    nationalParkMap = osm.viz.RenderMap(geojson_path = nationalParks.result.output_path, title = "National Parks", color = "#2ecc71")

    // -- Large cities map (was LargeCitiesMapFromCache)
    largeCities = osm.Population.FilterByPopulation(input_path = populationData.output_path, min_population = 10000, place_type = "city", operator = "gte")
    largeCitiesMap = osm.viz.RenderMap(geojson_path = largeCities.result.output_path, title = "Large Cities", color = "#e74c3c")

    // -- City analysis: filter + stats + map (was CityAnalysisFromCache)
    analysisCities = osm.Population.FilterByPopulation(input_path = populationData.output_path, min_population = 100000, place_type = "city", operator = "gte")
    cityStats = osm.Population.PopulationStatistics(input_path = analysisCities.result.output_path, place_type = "city")
    cityMap = osm.viz.RenderMap(geojson_path = analysisCities.result.output_path, title = "Cities", color = "#3498db")

    // -- Transport map: bicycle layer (was TransportMapFromCache)
    transportMap = osm.viz.RenderMap(geojson_path = bicycleRoutes.result.output_path, title = "Transport - Bicycle", color = "#27ae60")

    // -- Discover cities/towns/villages (was DiscoverCitiesAndTownsFromCache)
    discoverCities = osm.Population.FilterByPopulation(input_path = populationData.output_path, min_population = 0, place_type = "city", operator = "gte")
    discoverTowns = osm.Population.FilterByPopulation(input_path = populationData.output_path, min_population = 0, place_type = "town", operator = "gte")
    discoverVillages = osm.Population.FilterByPopulation(input_path = populationData.output_path, min_population = 0, place_type = "village", operator = "gte")
    discoverMap = osm.viz.RenderMap(geojson_path = discoverCities.result.output_path, title = "Cities and Towns", color = "#e74c3c")

    // -- State boundaries map (was StateBoundariesWithStatsFromCache)
    boundaryMap = osm.viz.RenderMap(geojson_path = boundariesData.output_path, title = "State Boundaries", color = "#9b59b6")

    // -- Regional analysis: reuses parks/routes/population data (was RegionalAnalysisFromCache)
    regionalCityStats = osm.Population.PopulationStatistics(input_path = populationData.output_path, place_type = "city")
    parksMap = osm.viz.RenderMap(geojson_path = parksData.output_path, title = "Regional Overview - Parks", color = "#2ecc71")

    yield AnalyzeRegion(completed_region = $.region)
  }

  /** Runs AnalyzeRegion for all 50 US states plus DC. */
  workflow AnalyzeAllStates() => (states_completed: Long) andThen {
    alabama = AnalyzeRegion(region = "Alabama")
    alaska = AnalyzeRegion(region = "Alaska")
    arizona = AnalyzeRegion(region = "Arizona")
    arkansas = AnalyzeRegion(region = "Arkansas")
    california = AnalyzeRegion(region = "California")
    colorado = AnalyzeRegion(region = "Colorado")
    connecticut = AnalyzeRegion(region = "Connecticut")
    delaware = AnalyzeRegion(region = "Delaware")
    districtOfColumbia = AnalyzeRegion(region = "DistrictOfColumbia")
    florida = AnalyzeRegion(region = "Florida")
    georgia = AnalyzeRegion(region = "GeorgiaUS")
    hawaii = AnalyzeRegion(region = "Hawaii")
    idaho = AnalyzeRegion(region = "Idaho")
    illinois = AnalyzeRegion(region = "Illinois")
    indiana = AnalyzeRegion(region = "Indiana")
    iowa = AnalyzeRegion(region = "Iowa")
    kansas = AnalyzeRegion(region = "Kansas")
    kentucky = AnalyzeRegion(region = "Kentucky")
    louisiana = AnalyzeRegion(region = "Louisiana")
    maine = AnalyzeRegion(region = "Maine")
    maryland = AnalyzeRegion(region = "Maryland")
    massachusetts = AnalyzeRegion(region = "Massachusetts")
    michigan = AnalyzeRegion(region = "Michigan")
    minnesota = AnalyzeRegion(region = "Minnesota")
    mississippi = AnalyzeRegion(region = "Mississippi")
    missouri = AnalyzeRegion(region = "Missouri")
    montana = AnalyzeRegion(region = "Montana")
    nebraska = AnalyzeRegion(region = "Nebraska")
    nevada = AnalyzeRegion(region = "Nevada")
    newHampshire = AnalyzeRegion(region = "NewHampshire")
    newJersey = AnalyzeRegion(region = "NewJersey")
    newMexico = AnalyzeRegion(region = "NewMexico")
    newYork = AnalyzeRegion(region = "NewYork")
    northCarolina = AnalyzeRegion(region = "NorthCarolina")
    northDakota = AnalyzeRegion(region = "NorthDakota")
    ohio = AnalyzeRegion(region = "Ohio")
    oklahoma = AnalyzeRegion(region = "Oklahoma")
    oregon = AnalyzeRegion(region = "Oregon")
    pennsylvania = AnalyzeRegion(region = "Pennsylvania")
    rhodeIsland = AnalyzeRegion(region = "RhodeIsland")
    southCarolina = AnalyzeRegion(region = "SouthCarolina")
    southDakota = AnalyzeRegion(region = "SouthDakota")
    tennessee = AnalyzeRegion(region = "Tennessee")
    texas = AnalyzeRegion(region = "Texas")
    utah = AnalyzeRegion(region = "Utah")
    vermont = AnalyzeRegion(region = "Vermont")
    virginia = AnalyzeRegion(region = "Virginia")
    washington = AnalyzeRegion(region = "Washington")
    westVirginia = AnalyzeRegion(region = "WestVirginia")
