// Population pipeline integration test workflow
//
// A 5-step pipeline: ResolveRegion -> Download -> ExtractPlacesWithPopulation ->
// FilterByPopulationRange -> PopulationStatistics
//
// ResolveRegion now yields a single `region: Region` (the legacy
// `(cache, resolution)` shape was retired in the cross-region migration), so
// the download is an explicit `osm.cache.Download(region = resolved.region)`
// step and the region name comes from `resolved.region.name`.
//
// Prerequisites: Compile with osmtypes.afl, osmregion.afl,
//   osmcache_download.afl, osmfilters_population.afl

/** Integration test for the end-to-end population analysis pipeline. */
namespace test.population {
    use osm.types
    use osm.Region
    use osm.cache
    use osm.Population

    /** Resolves a region, downloads its extract, extracts cities, filters by population range, and computes statistics. */
    workflow PopulationPipeline(
        region: String,
        min_population: Long = 0,
        max_population: Long = 10000000,
        prefer_continent: String = ""
    ) => (
        region_name: String,
        feature_count: Long,
        total_places: Long,
        total_population: Long,
        avg_population: Long
    ) andThen {
        // 1. Resolve region name to a typed Region
        resolved = ResolveRegion(name = $.region, prefer_continent = $.prefer_continent)

        // 2. Download (or reuse cached) the Geofabrik PBF for the region
        cached = osm.cache.Download(region = resolved.region)

        // 3. Extract all cities with population from the OSM data
        cities = ExtractPlacesWithPopulation(
            cache = cached.cache,
            place_type = "city",
            min_population = $.min_population
        )

        // 4. Filter to the desired population range
        filtered = FilterByPopulationRange(
            input_path = cities.result.output_path,
            min_population = $.min_population,
            max_population = $.max_population
        )

        // 5. Get population statistics for the filtered set
        stats = PopulationStatistics(
            input_path = filtered.result.output_path,
            place_type = "city"
        )

        yield PopulationPipeline(
            region_name = resolved.region.name,
            feature_count = filtered.result.feature_count,
            total_places = stats.stats.total_places,
            total_population = stats.stats.total_population,
            avg_population = stats.stats.avg_population
        )
    }
}


// Test workflow for region resolution integration test
//
// Wraps the ResolveRegion event facet in a simple workflow so we can
// execute it through the Evaluator + AgentPoller pipeline.
//
// Prerequisites: Compile with osmtypes.afl, osmregion.afl

/** Integration test that wraps ResolveRegion in a workflow for end-to-end execution. */
namespace test.region {
    use osm.types
    use osm.Region

    /** Resolves a geographic name to its Geofabrik download path and metadata.
     *
     *  ResolveRegion now yields a single `region: Region` (the legacy
     *  `(cache, resolution)` shape was retired in the cross-region migration),
     *  so the workflow maps its outputs from `resolved.region.*`. The output
     *  field names are kept (`matched_name`, `continent`, `geofabrik_path`)
     *  for the test assertions; `matched_name` maps to `region.name`. */
    workflow ResolveRegionTest(
        name: String,
        prefer_continent: String = ""
    ) => (
        matched_name: String,
        continent: String,
        geofabrik_path: String
    ) andThen {
        resolved = ResolveRegion(name = $.name, prefer_continent = $.prefer_continent)

        yield ResolveRegionTest(
            matched_name = resolved.region.name,
            continent = resolved.region.continent,
            geofabrik_path = resolved.region.geofabrik_path
        )
    }
}
